    def _read_int_setting(settings: QSettings, key: str, default: int) -> int:
        try:
            return int(settings.value(key, default))
        except (TypeError, ValueError):
            return int(default)

    def _read_bool_setting(settings: QSettings, key: str, default: bool) -> bool:
        value = settings.value(key, default)
        if isinstance(value, bool):
            return value
        return str(value).strip().lower() in {"1", "true", "yes", "on"}

    def apply_app_theme(app: QApplication, settings: QSettings, theme_key: str) -> str:
        resolved_theme = theme_key if theme_key in UI_THEME_SCHEMES else DEFAULT_UI_THEME
        ui_font_family = str(settings.value("appearance/ui_font_family", DEFAULT_UI_FONT_FAMILY) or DEFAULT_UI_FONT_FAMILY)
        base_font_size = max(
            UI_FONT_SIZE_MIN,
            min(UI_FONT_SIZE_MAX, _read_int_setting(settings, "appearance/ui_font_size", DEFAULT_UI_FONT_SIZE)),
        )
        data_font_size = max(
            UI_FONT_SIZE_MIN,
            min(UI_FONT_SIZE_MAX, _read_int_setting(settings, "appearance/data_font_size", DEFAULT_UI_DATA_FONT_SIZE)),
        )
        density_key = str(settings.value("appearance/ui_density", DEFAULT_UI_DENSITY) or DEFAULT_UI_DENSITY)
        app_font = QFont(app.font())
        app_font.setFamily(ui_font_family)
        app_font.setPointSize(base_font_size)
        app.setFont(app_font)
        app.setPalette(build_app_palette(resolved_theme))
        app.setStyleSheet(
            build_app_stylesheet(
                resolved_theme,
                base_font_size=base_font_size,
                data_font_size=data_font_size,
                density_key=density_key,
            )
        )
        return resolved_theme

    def build_monospace_font(settings: QSettings) -> QFont:
        point_size = _read_int_setting(settings, "appearance/log_font_size", DEFAULT_UI_LOG_FONT_SIZE)
        selected_family = str(
            settings.value("appearance/log_font_family", DEFAULT_UI_LOG_FONT_FAMILY) or DEFAULT_UI_LOG_FONT_FAMILY
        )
        bold_enabled = _read_bool_setting(settings, "appearance/log_font_bold", DEFAULT_UI_LOG_FONT_BOLD)
        fallback_order = [selected_family] + [family for family in LOG_FONT_FAMILY_OPTIONS if family != selected_family]
        font = QFont(fallback_order[0])
        for family in fallback_order:
            candidate = QFont(family)
            if candidate.exactMatch():
                font = candidate
                break
        font.setStyleHint(QFont.Monospace)
        font.setPointSize(point_size)
        font.setBold(bold_enabled)
        return font

    def read_log_text_style(settings: QSettings) -> str:
        value = str(
            settings.value("appearance/log_text_style", DEFAULT_UI_LOG_TEXT_STYLE)
            or DEFAULT_UI_LOG_TEXT_STYLE
        ).strip().lower()
        allowed = {key for key, _label in UI_LOG_TEXT_STYLE_OPTIONS}
        return value if value in allowed else DEFAULT_UI_LOG_TEXT_STYLE

    def read_text_color_scheme(settings: QSettings, key: str, default: str) -> str:
        value = str(settings.value(key, default) or default).strip().lower()
        allowed = {scheme_key for scheme_key, _label in UI_TEXT_COLOR_SCHEME_OPTIONS}
        return value if value in allowed else default

    def apply_window_text_highlight_style(window: "MainWindow") -> None:
        style = read_log_text_style(window.settings)
        log_scheme = read_text_color_scheme(
            window.settings,
            "appearance/log_color_scheme",
            DEFAULT_UI_LOG_COLOR_SCHEME,
        )
        preview_scheme = read_text_color_scheme(
            window.settings,
            "appearance/preview_color_scheme",
            DEFAULT_UI_PREVIEW_COLOR_SCHEME,
        )
        for highlighter in (
            window.log_highlighter,
            window.archive_log_highlighter,
            window.text_search_tab.log_highlighter,
        ):
            if hasattr(highlighter, "set_highlight_style"):
                highlighter.set_highlight_style(style)
            if hasattr(highlighter, "set_color_scheme"):
                highlighter.set_color_scheme(log_scheme)
        for editor in (
            window.archive_preview_text_edit,
            window.archive_preview_details_edit,
            window.text_search_tab.preview_text_edit,
        ):
            if hasattr(editor, "set_highlight_style"):
                editor.set_highlight_style(style)
            if hasattr(editor, "set_color_scheme"):
                editor.set_color_scheme(preview_scheme)

    def apply_window_data_fonts(window: "MainWindow") -> None:
        log_font = build_monospace_font(window.settings)
        window.log_view.setFont(log_font)
        window.log_view.document().setDefaultFont(log_font)
        window.archive_log_view.setFont(log_font)
        window.archive_log_view.document().setDefaultFont(log_font)
        window.archive_preview_text_edit.apply_font_preferences(log_font, preserve_size=False)
        window.archive_preview_details_edit.apply_font_preferences(log_font, preserve_size=False)
        window.archive_preview_info_edit.setFont(log_font)
        window.archive_preview_info_edit.document().setDefaultFont(log_font)
        window.text_search_tab.log_view.setFont(log_font)
        window.text_search_tab.log_view.document().setDefaultFont(log_font)
        window.text_search_tab.preview_text_edit.apply_font_preferences(log_font, preserve_size=False)
        window.replace_assistant_tab.log_view.setFont(log_font)
        window.replace_assistant_tab.log_view.document().setDefaultFont(log_font)
        window.replace_assistant_tab.preview_details_edit.setFont(log_font)
        window.replace_assistant_tab.preview_details_edit.document().setDefaultFont(log_font)
        bold_enabled = _read_bool_setting(window.settings, "appearance/log_font_bold", DEFAULT_UI_LOG_FONT_BOLD)
        window.log_highlighter.set_bold_enabled(bold_enabled)
        window.archive_log_highlighter.set_bold_enabled(bold_enabled)
        window.text_search_tab.log_highlighter.set_bold_enabled(bold_enabled)
        apply_window_text_highlight_style(window)

    class ScanWorker(QObject):
        log_message = Signal(str)
        result_ready = Signal(int)
        error = Signal(str)
        finished = Signal()

        def __init__(self, config: AppConfig):
            super().__init__()
            self.config = config
            self.stop_event = threading.Event()

        def stop(self) -> None:
            self.stop_event.set()

        @Slot()
        def run(self) -> None:
            try:
                self.log_message.emit("Scanning DDS files...")
                result = scan_dds_files(self.config, stop_event=self.stop_event)
                self.result_ready.emit(result.total_files)
                self.log_message.emit(f"Scan complete. Found {result.total_files} DDS files.")
            except Exception as exc:
                self.error.emit(str(exc))
            finally:
                self.finished.emit()

    class ArchiveScanWorker(QObject):
        log_message = Signal(str)
        progress_changed = Signal(int, int, str)
        completed = Signal(object)
        error = Signal(str)
        finished = Signal()

        def __init__(
            self,
            package_root: Path,
            cache_root: Path,
            *,
            force_refresh: bool = False,
            build_tree_index: bool = True,
            filter_text: str = "",
            exclude_filter_text: str = "",
            extension_filter: str = "*",
            package_filter_text: str = "",
            structure_filter: str = "",
            role_filter: str = "all",
            exclude_common_technical_suffixes: bool = False,
            min_size_kb: int = 0,
            previewable_only: bool = False,
            item_search_aliases: Optional[Mapping[str, str]] = None,
        ):
            super().__init__()
            self.package_root = package_root
            self.cache_root = cache_root
            self.force_refresh = force_refresh
            self.build_tree_index = build_tree_index
            self.filter_text = filter_text
            self.exclude_filter_text = exclude_filter_text
            self.extension_filter = extension_filter
            self.package_filter_text = package_filter_text
            self.structure_filter = structure_filter
            self.role_filter = role_filter
            self.exclude_common_technical_suffixes = exclude_common_technical_suffixes
            self.min_size_kb = min_size_kb
            self.previewable_only = previewable_only
            self.item_search_aliases = dict(item_search_aliases or {})
            self.stop_event = threading.Event()

        def stop(self) -> None:
            self.stop_event.set()

        @Slot()
        def run(self) -> None:
            try:
                timings: Dict[str, float] = {}
                started_at = time.perf_counter()
                if self.force_refresh:
                    self.log_message.emit(f"Refreshing archive packages under {self.package_root}")
                else:
                    self.log_message.emit(f"Loading archive packages under {self.package_root}")
                entries, source, cache_path, timings = scan_archive_entries_cached(
                    self.package_root,
                    self.cache_root,
                    force_refresh=self.force_refresh,
                    on_log=self.log_message.emit,
                    on_progress=self.progress_changed.emit,
                    stop_event=self.stop_event,
                )
                item_index_started_at = time.perf_counter()
                item_search_aliases: Dict[str, str] = {}
                item_display_names: Dict[str, str] = {}
                try:
                    item_index = build_archive_item_search_index(
                        entries,
                        on_log=self.log_message.emit,
                        stop_event=self.stop_event,
                    )
                    item_search_aliases = dict(item_index.model_base_aliases)
                    item_display_names = dict(getattr(item_index, "model_base_display_names", {}) or {})
                except RunCancelled:
                    raise
                except Exception as exc:
                    self.log_message.emit(f"Warning: item-name search index unavailable: {exc}")
                timings["item_search_index_s"] = max(0.0, float(time.perf_counter() - item_index_started_at))
                self.log_message.emit("Preparing archive browser state from loaded entries...")
                browser_state_started_at = time.perf_counter()
                browser_state = prepare_archive_browser_state(
                    entries,
                    filter_text=self.filter_text,
                    exclude_filter_text=self.exclude_filter_text,
                    extension_filter=self.extension_filter,
                    package_filter_text=self.package_filter_text,
                    structure_filter=self.structure_filter,
                    role_filter=self.role_filter,
                    exclude_common_technical_suffixes=self.exclude_common_technical_suffixes,
                    min_size_kb=self.min_size_kb,
                    previewable_only=self.previewable_only,
                    item_search_aliases=item_search_aliases,
                    build_structure_children=True,
                    build_tree_index=self.build_tree_index,
                    on_progress=self.progress_changed.emit,
                    stop_event=self.stop_event,
                )
                timings["browser_state_s"] = max(0.0, float(time.perf_counter() - browser_state_started_at))
                path_index_started_at = time.perf_counter()
                path_index = build_archive_entry_path_index(entries)
                timings["entry_path_index_s"] = max(0.0, float(time.perf_counter() - path_index_started_at))
                basename_index_started_at = time.perf_counter()
                basename_index = build_archive_entry_basename_index(entries)
                timings["entry_basename_index_s"] = max(0.0, float(time.perf_counter() - basename_index_started_at))
                extension_index_started_at = time.perf_counter()
                extension_index = build_archive_entry_extension_index(entries)
                timings["entry_extension_index_s"] = max(0.0, float(time.perf_counter() - extension_index_started_at))
                timings["total_s"] = max(0.0, float(time.perf_counter() - started_at))
                timing_summary = _format_timing_summary(
                    "Archive scan timings",
                    source,
                    timings,
                    (
                        ("cache_check_s", "cache_check"),
                        ("cache_load_s", "cache_load"),
                        ("archive_scan_s", "archive_scan"),
                        ("cache_write_s", "cache_write"),
                        ("item_search_index_s", "item_search"),
                        ("browser_state_s", "browser_state"),
                        ("entry_path_index_s", "path_index"),
                        ("entry_basename_index_s", "basename_index"),
                        ("entry_extension_index_s", "extension_index"),
                        ("total_s", "total"),
                    ),
                )
                self.completed.emit(
                    {
                        "entries": entries,
                        "source": source,
                        "cache_path": str(cache_path) if cache_path is not None else "",
                        "browser_state": browser_state,
                        "path_index": path_index,
                        "basename_index": basename_index,
                        "extension_index": extension_index,
                        "item_search_aliases": item_search_aliases,
                        "item_display_names": item_display_names,
                        "timings": timings,
                        "timing_summary": timing_summary,
                    }
                )
            except RunCancelled as exc:
                if not self.stop_event.is_set():
                    self.error.emit(str(exc))
            except Exception as exc:
                self.error.emit(str(exc))
            finally:
                self.finished.emit()

    class ArchiveSidecarIndexWorker(QObject):
        log_message = Signal(str)
        progress_changed = Signal(int, int, int, str)
        completed = Signal(int, object)
        error = Signal(int, str)
        finished = Signal(int)

        def __init__(
            self,
            request_id: int,
            package_root: Path,
            cache_root: Path,
            entries: Sequence[ArchiveEntry],
            sidecar_worker_count: int = 0,
        ):
            super().__init__()
            self.request_id = int(request_id)
            self.package_root = package_root
            self.cache_root = cache_root
            self.entries = entries
            self.sidecar_worker_count = max(0, min(16, int(sidecar_worker_count or 0)))
            self.stop_event = threading.Event()

        def stop(self) -> None:
            self.stop_event.set()

        @Slot()
        def run(self) -> None:
            try:
                timings: Dict[str, float] = {}
                started_at = time.perf_counter()
                last_progress_emit_at = 0.0

                def _emit_throttled_progress(current: int, total: int, detail: str) -> None:
                    nonlocal last_progress_emit_at
                    now = time.perf_counter()
                    if total > 0 and current >= total:
                        last_progress_emit_at = now
                        self.progress_changed.emit(self.request_id, current, total, detail)
                        return
                    if now - last_progress_emit_at < 0.75:
                        return
                    last_progress_emit_at = now
                    self.progress_changed.emit(self.request_id, current, total, detail)

                self.log_message.emit("Checking texture sidecar cache metadata...")
                self.progress_changed.emit(
                    self.request_id,
                    0,
                    0,
                    "Checking cache metadata...",
                )
                cached = load_archive_texture_sidecar_cache_rows(
                    self.package_root,
                    self.cache_root,
                    self.entries,
                    worker_count=self.sidecar_worker_count,
                    on_log=self.log_message.emit,
                    stop_event=self.stop_event,
                    timings=timings,
                    on_progress=_emit_throttled_progress,
                )
                if cached is not None:
                    path_rows, basename_rows = cached
                    lazy_index_started_at = time.perf_counter()
                    self.progress_changed.emit(
                        self.request_id,
                        0,
                        0,
                        "Loading cache rows complete. Preparing lazy lookup indexes...",
                    )
                    sidecar_entries_by_texture_path = build_lazy_archive_texture_sidecar_entry_index(
                        path_rows,
                        self.entries,
                    )
                    sidecar_entries_by_texture_basename = build_lazy_archive_texture_sidecar_entry_index(
                        basename_rows,
                        self.entries,
                    )
                    timings["lazy_index_s"] = max(0.0, float(time.perf_counter() - lazy_index_started_at))
                    timings.setdefault("path_row_build_s", 0.0)
                    timings.setdefault("basename_row_build_s", 0.0)
                    timings.setdefault("entry_resolve_s", 0.0)
                    timings.setdefault("cache_write_s", 0.0)
                    timings["total_s"] = max(0.0, float(time.perf_counter() - started_at))
                    timing_summary = _format_timing_summary(
                        "Texture sidecar timings",
                        "cache",
                        timings,
                        (
                            ("cache_check_s", "cache_check"),
                            ("cache_load_s", "cache_load"),
                            ("incremental_remap_s", "remap"),
                            ("incremental_scan_s", "rescan_changed"),
                            ("incremental_update_s", "incremental_update"),
                            ("path_row_build_s", "path_rows"),
                            ("basename_row_build_s", "basename_rows"),
                            ("lazy_index_s", "lazy_index"),
                            ("entry_resolve_s", "resolve"),
                            ("cache_write_s", "cache_write"),
                            ("total_s", "total"),
                        ),
                    )
                    self.completed.emit(
                        self.request_id,
                        {
                            "sidecar_entries_by_texture_path": sidecar_entries_by_texture_path,
                            "sidecar_entries_by_texture_basename": sidecar_entries_by_texture_basename,
                            "sidecar_path_rows": path_rows,
                            "sidecar_basename_rows": basename_rows,
                            "source": "cache",
                            "cache_path": str(resolve_archive_sidecar_cache_path(self.package_root, self.cache_root)),
                            "timings": timings,
                            "timing_summary": timing_summary,
                        },
                    )
                    return

                self.log_message.emit("Indexing texture sidecar bindings for related-file discovery...")
                self.progress_changed.emit(
                    self.request_id,
                    0,
                    0,
                    "Indexing sidecar files...",
                )
                path_rows_started_at = time.perf_counter()
                path_rows = build_archive_texture_sidecar_path_rows(
                    self.entries,
                    worker_count=self.sidecar_worker_count,
                    stop_event=self.stop_event,
                    on_progress=_emit_throttled_progress,
                    timings=timings,
                )
                timings["path_row_build_s"] = max(0.0, float(time.perf_counter() - path_rows_started_at))
                self.progress_changed.emit(
                    self.request_id,
                    0,
                    0,
                    "Building basename lookup...",
                )
                basename_rows_started_at = time.perf_counter()
                basename_rows = build_archive_texture_sidecar_basename_rows(path_rows)
                timings["basename_row_build_s"] = max(0.0, float(time.perf_counter() - basename_rows_started_at))
                lazy_index_started_at = time.perf_counter()
                self.progress_changed.emit(
                    self.request_id,
                    0,
                    0,
                    "Preparing lazy sidecar lookup indexes...",
                )
                sidecar_entries_by_texture_path = build_lazy_archive_texture_sidecar_entry_index(path_rows, self.entries)
                sidecar_entries_by_texture_basename = build_lazy_archive_texture_sidecar_entry_index(
                    basename_rows,
                    self.entries,
                )
                timings["lazy_index_s"] = max(0.0, float(time.perf_counter() - lazy_index_started_at))
                timings["entry_resolve_s"] = 0.0
                if self.stop_event.is_set():
                    return
                cache_path_text = ""
                try:
                    self.progress_changed.emit(
                        self.request_id,
                        0,
                        0,
                        "Writing cache...",
                    )
                    cache_path = save_archive_texture_sidecar_cache(
                        self.package_root,
                        self.cache_root,
                        self.entries,
                        path_rows=path_rows,
                        basename_rows=None,
                        on_log=self.log_message.emit,
                        on_progress=lambda current, total, detail: self.progress_changed.emit(
                            self.request_id,
                            current,
                            total,
                            detail,
                        ),
                        stop_event=self.stop_event,
                        timings=timings,
                    )
                    cache_path_text = str(cache_path)
                except Exception as exc:
                    if not self.stop_event.is_set():
                        self.log_message.emit(f"Warning: texture sidecar cache could not be written: {exc}")
                    timings.setdefault("cache_write_s", 0.0)
                self.progress_changed.emit(self.request_id, 1, 1, "Texture sidecar cache is ready.")
                timings["total_s"] = max(0.0, float(time.perf_counter() - started_at))
                timing_summary = _format_timing_summary(
                    "Texture sidecar timings",
                    "scan",
                    timings,
                    (
                        ("cache_check_s", "cache_check"),
                        ("cache_load_s", "cache_load"),
                        ("path_row_build_s", "path_rows"),
                        ("basename_row_build_s", "basename_rows"),
                        ("lazy_index_s", "lazy_index"),
                        ("entry_resolve_s", "resolve"),
                        ("cache_write_s", "cache_write"),
                        ("total_s", "total"),
                    ),
                )
                if not self.stop_event.is_set():
                    self.completed.emit(
                        self.request_id,
                        {
                            "sidecar_entries_by_texture_path": sidecar_entries_by_texture_path,
                            "sidecar_entries_by_texture_basename": sidecar_entries_by_texture_basename,
                            "sidecar_path_rows": path_rows,
                            "sidecar_basename_rows": basename_rows,
                            "source": "scan",
                            "cache_path": cache_path_text,
                            "timings": timings,
                            "timing_summary": timing_summary,
                        },
                    )
            except RunCancelled as exc:
                if not self.stop_event.is_set():
                    self.error.emit(self.request_id, str(exc))
            except Exception as exc:
                if not self.stop_event.is_set():
                    self.error.emit(self.request_id, str(exc))
            finally:
                self.finished.emit(self.request_id)

    class ArchiveFilterWorker(QObject):
        progress_changed = Signal(int, int, str)
        completed = Signal(object)
        error = Signal(str)
        finished = Signal()

        def __init__(
            self,
            entries: Sequence[ArchiveEntry],
            *,
            entries_by_extension: Optional[Dict[str, Sequence[ArchiveEntry]]] = None,
            request_signature: Tuple[object, ...] = (),
            preferred_path: str = "",
            build_tree_index: bool = True,
            filter_text: str = "",
            exclude_filter_text: str = "",
            extension_filter: str = "*",
            package_filter_text: str = "",
            structure_filter: str = "",
            role_filter: str = "all",
            exclude_common_technical_suffixes: bool = False,
            min_size_kb: int = 0,
            previewable_only: bool = False,
            item_search_aliases: Optional[Mapping[str, str]] = None,
        ):
            super().__init__()
            # Keep references instead of copying 1M+ archive entries on the UI thread
            # before the worker even starts running.
            self.entries = entries
            self.entries_by_extension = entries_by_extension or {}
            self.request_signature = tuple(request_signature or ())
            self.preferred_path = preferred_path
            self.build_tree_index = build_tree_index
            self.filter_text = filter_text
            self.exclude_filter_text = exclude_filter_text
            self.extension_filter = extension_filter
            self.package_filter_text = package_filter_text
            self.structure_filter = structure_filter
            self.role_filter = role_filter
            self.exclude_common_technical_suffixes = exclude_common_technical_suffixes
            self.min_size_kb = min_size_kb
            self.previewable_only = previewable_only
            self.item_search_aliases = dict(item_search_aliases or {})
            self.stop_event = threading.Event()

        def stop(self) -> None:
            self.stop_event.set()

        @Slot()
        def run(self) -> None:
            try:
                source_entries = self.entries
                normalized_extension = normalize_archive_extension_filter(self.extension_filter)
                if normalized_extension and normalized_extension not in {"*", "all", ".*"} and self.entries_by_extension:
                    source_entries = self.entries_by_extension.get(normalized_extension, [])
                browser_state = prepare_archive_browser_state(
                    source_entries,
                    filter_text=self.filter_text,
                    exclude_filter_text=self.exclude_filter_text,
                    extension_filter=self.extension_filter,
                    package_filter_text=self.package_filter_text,
                    structure_filter=self.structure_filter,
                    role_filter=self.role_filter,
                    exclude_common_technical_suffixes=self.exclude_common_technical_suffixes,
                    min_size_kb=self.min_size_kb,
                    previewable_only=self.previewable_only,
                    item_search_aliases=self.item_search_aliases,
                    build_structure_children=False,
                    build_tree_index=self.build_tree_index,
                    on_progress=self.progress_changed.emit,
                    stop_event=self.stop_event,
                )
                self.completed.emit(
                    {
                        "browser_state": browser_state,
                        "request_signature": self.request_signature,
                        "preferred_path": self.preferred_path,
                    }
                )
            except RunCancelled:
                pass
            except Exception as exc:
                self.error.emit(str(exc))
            finally:
                self.finished.emit()

