        def _sync_model_preview_settings_dialog(self) -> None:
            dialog = getattr(self, "model_preview_settings_dialog", None)
            if dialog is None:
                return
            dialog.set_settings(self._current_model_preview_render_settings())
            dialog.set_archive_performance_settings(self._current_archive_performance_settings())

        def _sync_archive_performance_settings_controls(self) -> None:
            settings_tab = getattr(self, "settings_tab", None)
            if settings_tab is not None and hasattr(settings_tab, "sync_archive_performance_controls"):
                settings_tab.sync_archive_performance_controls(self._current_archive_performance_settings())
            dialog = getattr(self, "model_preview_settings_dialog", None)
            if dialog is not None:
                dialog.set_archive_performance_settings(self._current_archive_performance_settings())

        def _open_model_preview_settings_dialog(self) -> None:
            dialog = getattr(self, "model_preview_settings_dialog", None)
            if dialog is None:
                dialog = ModelPreviewSettingsDialog(
                    settings=self._current_model_preview_render_settings(),
                    archive_performance_settings=self._current_archive_performance_settings(),
                    parent=self,
                )
                dialog.settings_changed.connect(self._handle_model_preview_settings_changed)
                dialog.archive_performance_changed.connect(self._handle_archive_performance_settings_changed)
                dialog.clear_preview_cache_requested.connect(self._handle_clear_archive_preview_cache_requested)
                self.model_preview_settings_dialog = dialog
            else:
                dialog.set_settings(self._current_model_preview_render_settings())
                dialog.set_archive_performance_settings(self._current_archive_performance_settings())
            dialog.show()
            dialog.raise_()
            dialog.activateWindow()

        def _open_modal_model_preview_settings_dialog(self, parent_dialog: QDialog) -> None:
            dialog = ModelPreviewSettingsDialog(
                settings=self._current_model_preview_render_settings(),
                archive_performance_settings=self._current_archive_performance_settings(),
                parent=parent_dialog,
            )
            dialog.setAttribute(Qt.WA_DeleteOnClose, True)
            dialog.setWindowModality(Qt.WindowModal)
            dialog.settings_changed.connect(self._handle_model_preview_settings_changed)
            dialog.archive_performance_changed.connect(self._handle_archive_performance_settings_changed)
            dialog.clear_preview_cache_requested.connect(self._handle_clear_archive_preview_cache_requested)
            active_dialogs = getattr(self, "_modal_model_preview_settings_dialogs", None)
            if active_dialogs is None:
                active_dialogs = []
                self._modal_model_preview_settings_dialogs = active_dialogs
            active_dialogs.append(dialog)
            dialog.destroyed.connect(
                lambda *_args, modal_dialog=dialog, dialogs=active_dialogs: dialogs.remove(modal_dialog)
                if modal_dialog in dialogs
                else None
            )
            dialog.show()
            dialog.raise_()
            dialog.activateWindow()

        def _handle_clear_archive_preview_cache_requested(self) -> None:
            cleared_count = len(self.archive_preview_cache)
            self._clear_archive_preview_cache()
            self.append_archive_log(f"Cleared {cleared_count:,} in-memory archive preview cache entr{'y' if cleared_count == 1 else 'ies'}.")
            self.set_status_message("Archive preview cache cleared.")

        def _configure_model_preview_widget(
            self,
            widget: ModelPreviewWidget,
            *,
            apply_toggle_defaults: bool,
        ) -> None:
            preview_settings = self._current_model_preview_render_settings()
            set_model_texture_display_preview_max_dimension(preview_settings.preview_texture_max_dimension)
            widget.set_render_settings(preview_settings)
            if apply_toggle_defaults:
                widget.set_use_textures(bool(preview_settings.use_textures_by_default))
                widget.set_high_quality_textures(bool(preview_settings.high_quality_by_default))

        def _schedule_current_model_preview_asset_refresh(self) -> None:
            current_entry = self._current_archive_entry()
            if current_entry is None or current_entry.extension not in ARCHIVE_MESH_EXTENSIONS:
                return
            self.model_preview_refresh_timer.start()

        def _refresh_current_model_preview_assets(self) -> None:
            current_entry = self._current_archive_entry()
            if current_entry is None or current_entry.extension not in ARCHIVE_MESH_EXTENSIONS:
                return
            include_loose_preview_assets = bool(
                self.archive_preview_requested_loose
                or (
                    self.current_archive_preview_result is not None
                    and bool(self.current_archive_preview_result.loose_file_path)
                )
            )
            self._clear_archive_preview_cache()
            self._render_archive_preview(
                current_entry,
                include_loose_preview_assets=include_loose_preview_assets,
                prefer_loose_preview=self.archive_preview_requested_loose,
            )

        def _handle_model_preview_settings_changed(self, settings: Optional[object] = None) -> None:
            previous_settings = self._current_model_preview_render_settings()
            preview_settings = settings if isinstance(settings, ModelPreviewRenderSettings) else self._current_model_preview_render_settings()
            preview_settings = clamp_model_preview_render_settings(preview_settings)
            self._model_preview_render_settings = preview_settings
            set_model_texture_display_preview_max_dimension(preview_settings.preview_texture_max_dimension)
            for widget in self.findChildren(ModelPreviewWidget):
                widget.set_render_settings(preview_settings)
                widget.set_use_textures(bool(preview_settings.use_textures_by_default))
                widget.set_high_quality_textures(bool(preview_settings.high_quality_by_default))
            if (
                previous_settings.preview_texture_max_dimension != preview_settings.preview_texture_max_dimension
                or previous_settings.visible_texture_mode != preview_settings.visible_texture_mode
            ):
                self._schedule_current_model_preview_asset_refresh()
            preview_model = None
            if self.current_archive_preview_result is not None and not self.archive_preview_showing_loose:
                preview_model = self.current_archive_preview_result.preview_model
            self._update_archive_model_action_controls(preview_model)
            self._refresh_archive_preview_settings_status()
            if self._settings_ready:
                self.schedule_settings_save()

        def _handle_archive_performance_settings_changed(self, settings: Optional[object] = None) -> None:
            performance_settings = (
                settings
                if isinstance(settings, ArchivePerformanceSettings)
                else self._current_archive_performance_settings()
            )
            performance_settings = clamp_archive_performance_settings(performance_settings)
            previous_cache_limit = int(self.archive_preview_cache_limit)
            previous_sidecar_indexing_enabled = self._current_archive_performance_settings().enable_sidecar_indexing
            self._archive_performance_settings = performance_settings
            self.archive_preview_cache_limit = performance_settings.preview_cache_limit
            self._sync_archive_performance_settings_controls()
            while len(self.archive_preview_cache) > self.archive_preview_cache_limit:
                self.archive_preview_cache.popitem(last=False)
            if previous_cache_limit != self.archive_preview_cache_limit:
                self.append_archive_log(f"Archive preview cache size set to {self.archive_preview_cache_limit}.")
            if previous_sidecar_indexing_enabled and not performance_settings.enable_sidecar_indexing:
                self.archive_sidecar_pending_start = False
                self.archive_browser_warmup_pending = False
                self.archive_tree.setEnabled(True)
                if self.archive_sidecar_worker is not None:
                    try:
                        self.archive_sidecar_worker.stop()
                    except Exception:
                        pass
                    self.append_archive_log("Texture sidecar indexing disabled; stopping the current sidecar index run.")
                self._set_archive_warmup_overlay(False)
                if self.archive_entries:
                    self._refresh_or_defer_archive_browser_view(
                        activate_tab=self._activate_archive_browser_on_scan_complete,
                    )
                    self._activate_archive_browser_on_scan_complete = False
                    self._refresh_or_defer_research_archive_picker()
                    ready_text = "Archive browsing ready. Global texture sidecar indexing is disabled."
                    self.archive_scan_progress_label.setText(ready_text)
                    self.archive_scan_progress_bar.setRange(0, 1)
                    self.archive_scan_progress_bar.setValue(1)
                    self.archive_scan_progress_bar.setFormat("Ready")
                    self.set_status_message(ready_text)
                    self.append_archive_log(ready_text)
                    if self.worker_thread is None:
                        self.set_busy(False, build_mode=False)
            elif (
                not previous_sidecar_indexing_enabled
                and performance_settings.enable_sidecar_indexing
                and self.archive_entries
                and self.archive_sidecar_thread is None
            ):
                self.archive_sidecar_pending_start = True
                self.append_archive_log("Texture sidecar indexing enabled; it will run in the background.")
                QTimer.singleShot(0, self._start_archive_sidecar_index_worker)
            if self._settings_ready:
                self.schedule_settings_save()

        def _quick_archive_model_preview_result(self, entry: Optional[ArchiveEntry]) -> Optional[ArchivePreviewResult]:
            if entry is None or entry.extension not in ARCHIVE_MESH_EXTENSIONS:
                return None
            sidecar_refs: List[ArchiveModelTextureReference] = []
            normalized_path = entry.path.replace("\\", "/").strip()
            source_stem = PurePosixPath(normalized_path).stem.strip()
            candidate_basenames: List[str] = []
            if source_stem:
                if entry.extension == ".pac":
                    candidate_basenames.append(f"{source_stem}.pac_xml")
                elif entry.extension == ".pam":
                    candidate_basenames.append(f"{source_stem}.pami")
                    candidate_basenames.append(f"{source_stem}.pam_xml")
                elif entry.extension == ".pamlod":
                    candidate_basenames.append(f"{source_stem}.pami")
                    candidate_basenames.append(f"{source_stem}.pamlod_xml")
            seen_paths: set[str] = set()
            for basename in candidate_basenames:
                for related_entry in self.archive_entries_by_basename.get(basename.lower(), ()):
                    normalized_related = related_entry.path.replace("\\", "/")
                    if normalized_related in seen_paths:
                        continue
                    seen_paths.add(normalized_related)
                    sidecar_refs.append(
                        ArchiveModelTextureReference(
                            reference_name=PurePosixPath(normalized_related).name,
                            semantic_label="Material Sidecar",
                            resolution_status="resolved",
                            resolved_archive_path=related_entry.path,
                            resolved_package_label=related_entry.package_label,
                            resolved_entry=related_entry,
                            usage_count=1,
                            reference_kind=RelationKind.MATERIAL_SIDECAR.value,
                            relation_group="Material Sidecars",
                            relation_reason="Same-stem material sidecar",
                            relation_confidence=RelationConfidence.DERIVED_SAME_STEM.value,
                        )
                    )
            detail_parts = [
                build_archive_entry_detail_text(
                    entry,
                    "Quick preview is showing metadata and same-stem material sidecars while the full 3D model preview builds in the background.",
                ),
                "Full preview loading...",
            ]
            if sidecar_refs:
                detail_parts.append(f"Found {len(sidecar_refs):,} likely material sidecar(s).")
            return ArchivePreviewResult(
                status="ok",
                title=entry.basename,
                metadata_summary=f"{build_archive_entry_metadata_summary(entry)} | Full preview loading...",
                detail_text="\n\n".join(part for part in detail_parts if part),
                model_texture_references=tuple(sidecar_refs),
                asset_family_graph=build_archive_asset_family_graph(entry, tuple(sidecar_refs)),
                preferred_view="info",
                sidecar_generation=self.archive_sidecar_generation,
            )

        @staticmethod
        def _archive_family_badge(path_value: str) -> str:
            normalized = str(path_value or "").replace("\\", "/").strip().lower()
            if not normalized:
                return "Unknown"
            parts = [part for part in PurePosixPath(normalized).parts if part]
            if parts and re.fullmatch(r"\d{4}", parts[0]):
                parts = parts[1:]
            joined = "/".join(parts)
            if joined.startswith("leveldata/"):
                return "Proxy LOD" if "/proxylod/" in joined else "Leveldata"
            if joined.startswith("effect/"):
                return "Effect"
            if joined.startswith("object/"):
                return "Object"
            if joined.startswith("ui/"):
                return "UI"
            if joined.startswith("tree/"):
                return "Tree"
            if joined.startswith("character/"):
                if "/2_mon/" in joined:
                    return "Monster"
                if "/4_riding/" in joined:
                    return "Riding"
                if "/3_npc/" in joined:
                    return "NPC"
                if "/1_pc/" in joined:
                    return "Character"
                if "/6_object/" in joined:
                    return "Character Object"
                return "Character"
            return "Unknown"

        @staticmethod
        def _archive_relation_confidence_label(value: str) -> str:
            normalized = str(value or "").strip().lower()
            return {
                RelationConfidence.AUTHORITATIVE.value: "Authoritative",
                RelationConfidence.EXACT_PATH.value: "Exact path",
                RelationConfidence.PATH_NORMALIZED.value: "Path normalized",
                RelationConfidence.CROSS_PACKAGE.value: "Cross-package",
                RelationConfidence.DERIVED_SAME_STEM.value: "Same basename",
                RelationConfidence.DERIVED_FAMILY_HEURISTIC.value: "Family skeleton",
            }.get(normalized, normalized.replace("_", " ").title() if normalized else "")

        @staticmethod
        def _archive_texture_reference_group_label(
            relation_group: str,
            reference_name: str,
            resolved_archive_path: str,
        ) -> str:
            group = str(relation_group or "").strip() or "Metadata / Other"
            if group != "Textures":
                return group
            path_text = str(resolved_archive_path or reference_name or "").replace("\\", "/").strip()
            normalized = path_text.lower().lstrip("/")
            if not normalized.startswith("leveldata/") or "/proxylod/" not in normalized:
                return group
            stem = PurePosixPath(normalized).stem
            for suffix in (
                "_normal",
                "_height",
                "_disp",
                "_diff",
                "_base",
                "_color",
                "_albedo",
                "_mask",
                "_rough",
                "_sp",
                "_ma",
                "_n",
                "_d",
            ):
                if stem.endswith(suffix):
                    stem = stem[: -len(suffix)]
                    break
            stem = stem.strip("_- ") or "unknown"
            return f"Proxy LOD Textures / {stem}"

        def _archive_texture_reference_status_text(self, reference: ArchiveModelTextureReference) -> str:
            status = str(getattr(reference, "resolution_status", "") or "").strip().lower()
            resolved_entry = getattr(reference, "resolved_entry", None)
            if status == "resolved":
                if isinstance(resolved_entry, ArchiveEntry) and resolved_entry.extension == ".dds" and resolved_entry.compression_type == 1:
                    return "Resolved (Partial)"
                return "Resolved"
            if status == "technical_only":
                return "Technical only"
            return "Missing"

        def _populate_archive_texture_reference_list(
            self,
            references: Sequence[ArchiveModelTextureReference],
        ) -> None:
            self.current_archive_model_texture_references = list(references)
            self.archive_texture_refs_tree.clear()
            group_items: Dict[str, QTreeWidgetItem] = {}
            for index, reference in enumerate(self.current_archive_model_texture_references):
                resolved_archive_path = str(getattr(reference, "resolved_archive_path", "") or "").strip()
                resolved_package_label = str(getattr(reference, "resolved_package_label", "") or "").strip()
                reference_name = str(getattr(reference, "reference_name", "") or "").strip()
                relation_group = self._archive_texture_reference_group_label(
                    str(getattr(reference, "relation_group", "") or "").strip() or "Metadata / Other",
                    reference_name,
                    resolved_archive_path,
                )
                group_item = group_items.get(relation_group)
                if group_item is None:
                    group_item = QTreeWidgetItem([relation_group, "", "", "", "", "", "", ""])
                    group_item.setFlags(Qt.ItemIsEnabled)
                    self.archive_texture_refs_tree.addTopLevelItem(group_item)
                    group_item.setExpanded(True)
                    group_items[relation_group] = group_item
                reference_display = reference_name or "-"
                if (
                    str(getattr(reference, "relation_group", "") or "").strip() == "Textures"
                    and resolved_archive_path.lower().endswith(".dds")
                    and not PurePosixPath(reference_display.replace("\\", "/")).suffix
                ):
                    reference_display = resolved_archive_path
                semantic_text = str(getattr(reference, "semantic_label", "") or "").strip() or "-"
                sidecar_parameter_name = str(getattr(reference, "sidecar_parameter_name", "") or "").strip()
                part_name = str(getattr(reference, "part_name", "") or "").strip()
                material_name = str(getattr(reference, "material_name", "") or "").strip()
                shader_family = str(getattr(reference, "shader_family", "") or "").strip()
                part_text = part_name or material_name or "-"
                if shader_family:
                    part_text = f"{part_text} / {shader_family}" if part_text != "-" else shader_family
                visual_state = str(getattr(reference, "visualization_state", "") or "").strip()
                texture_role = str(getattr(reference, "texture_role", "") or "").strip()
                relation_confidence = str(getattr(reference, "relation_confidence", "") or "").strip()
                relation_confidence_label = self._archive_relation_confidence_label(relation_confidence)
                slot_text = texture_role or semantic_text
                if str(getattr(reference, "relation_group", "") or "").strip() == "Textures" and sidecar_parameter_name:
                    slot_text = f"{slot_text} [{sidecar_parameter_name}]"
                item = QTreeWidgetItem(
                    [
                        reference_display,
                        self._archive_texture_reference_status_text(reference),
                        part_text,
                        slot_text,
                        visual_state or relation_confidence_label or "-",
                        resolved_archive_path or "-",
                        resolved_package_label or "-",
                        str(max(1, int(getattr(reference, "usage_count", 0) or 0))),
                    ]
                )
                if reference_name and reference_display != reference_name:
                    item.setToolTip(0, f"Original reference: {reference_name}\nResolved DDS: {resolved_archive_path}")
                if material_name:
                    item.setToolTip(0, "\n".join(part for part in [item.toolTip(0), f"Material: {material_name}"] if part))
                semantic_hint = str(getattr(reference, "semantic_hint", "") or "").strip()
                if semantic_hint:
                    item.setToolTip(3, semantic_hint)
                linked_mesh_path = str(getattr(reference, "linked_mesh_path", "") or "").strip()
                sidecar_kind = str(getattr(reference, "sidecar_kind", "") or "").strip()
                if sidecar_kind or linked_mesh_path or shader_family:
                    detail_lines = [
                        f"Sidecar: {sidecar_kind}" if sidecar_kind else "",
                        f"Linked mesh: {linked_mesh_path}" if linked_mesh_path else "",
                        f"Shader: {shader_family}" if shader_family else "",
                    ]
                    item.setToolTip(2, "\n".join(line for line in detail_lines if line))
                if visual_state:
                    item.setToolTip(4, visual_state)
                relation_reason = str(getattr(reference, "relation_reason", "") or "").strip()
                if relation_reason or relation_confidence_label:
                    reason_parts = [part for part in [relation_reason, relation_confidence_label] if part]
                    item.setToolTip(0, "\n".join(part for part in [item.toolTip(0), "Why: " + " | ".join(reason_parts)] if part))
                if resolved_archive_path:
                    item.setToolTip(5, resolved_archive_path)
                item.setData(0, Qt.UserRole, index)
                group_item.addChild(item)
            for relation_group, group_item in group_items.items():
                group_item.setText(0, f"{relation_group} ({group_item.childCount()})")
            self.archive_texture_refs_group.setVisible(bool(self.current_archive_model_texture_references))
            if self.current_archive_model_texture_references:
                total_width = max(1, self.archive_preview_content_splitter.width())
                sizes = self.archive_preview_content_splitter.sizes()
                right_width = max(260, min(500, int(total_width * 0.40)))
                left_width = max(300, total_width - right_width)
                if len(sizes) < 2 or sizes[1] < 260 or sum(sizes) > total_width + 80:
                    self.archive_preview_content_splitter.setSizes([left_width, right_width])
                self._layout_archive_texture_reference_columns()
                QTimer.singleShot(0, self._layout_archive_texture_reference_columns)
            else:
                self.archive_preview_content_splitter.setSizes([1, 0])
            self._update_archive_texture_reference_action_controls()

        def _layout_archive_texture_reference_columns(self, *_args) -> None:
            if not hasattr(self, "archive_texture_refs_tree"):
                return
            tree = self.archive_texture_refs_tree
            if tree.columnCount() < 8:
                return

            viewport_width = max(0, tree.viewport().width())
            available_width = max(viewport_width, 260)
            reference_width = 150
            status_width = 98
            part_width = 140
            slot_width = 126
            visual_width = 90
            package_width = 82
            uses_width = 52
            archive_width = max(
                160,
                available_width - (reference_width + status_width + part_width + slot_width + visual_width + package_width + uses_width + 12),
            )

            tree.setColumnWidth(0, reference_width)
            tree.setColumnWidth(1, status_width)
            tree.setColumnWidth(2, part_width)
            tree.setColumnWidth(3, slot_width)
            tree.setColumnWidth(4, visual_width)
            tree.setColumnWidth(5, archive_width)
            tree.setColumnWidth(6, package_width)
            tree.setColumnWidth(7, uses_width)

        def _handle_archive_preview_content_splitter_moved(self, *_args) -> None:
            if (
                hasattr(self, "archive_texture_refs_group")
                and self.archive_texture_refs_group.isVisible()
                and self.current_archive_model_texture_references
            ):
                sizes = self.archive_preview_content_splitter.sizes()
                if len(sizes) >= 2 and sizes[1] < 260:
                    total = max(1, sum(sizes))
                    right = max(260, min(420, total // 2))
                    self.archive_preview_content_splitter.setSizes([max(1, total - right), right])
            self._layout_archive_texture_reference_columns()

        def _current_archive_texture_reference(self) -> Optional[ArchiveModelTextureReference]:
            current_item = self.archive_texture_refs_tree.currentItem()
            if current_item is None:
                return None
            raw_index = current_item.data(0, Qt.UserRole)
            try:
                index = int(raw_index)
            except (TypeError, ValueError):
                return None
            if 0 <= index < len(self.current_archive_model_texture_references):
                return self.current_archive_model_texture_references[index]
            return None

        def _selected_archive_texture_references(self) -> List[ArchiveModelTextureReference]:
            selected_references: List[ArchiveModelTextureReference] = []
            seen_indices: set[int] = set()
            for item in self.archive_texture_refs_tree.selectedItems():
                raw_index = item.data(0, Qt.UserRole)
                try:
                    index = int(raw_index)
                except (TypeError, ValueError):
                    continue
                if index in seen_indices:
                    continue
                seen_indices.add(index)
                if 0 <= index < len(self.current_archive_model_texture_references):
                    selected_references.append(self.current_archive_model_texture_references[index])
            return selected_references

        def _resolved_archive_reference_entries(
            self,
            references: Sequence[ArchiveModelTextureReference],
        ) -> List[ArchiveEntry]:
            resolved_entries: List[ArchiveEntry] = []
            seen_paths: set[str] = set()
            for reference in references:
                resolved_entry = getattr(reference, "resolved_entry", None)
                if not isinstance(resolved_entry, ArchiveEntry):
                    continue
                normalized_path = resolved_entry.path.replace("\\", "/").strip().lower()
                if not normalized_path or normalized_path in seen_paths:
                    continue
                seen_paths.add(normalized_path)
                resolved_entries.append(resolved_entry)
            return resolved_entries

        def _current_or_related_material_sidecar_entry(self) -> Optional[ArchiveEntry]:
            current_entry = self._current_archive_entry()
            if isinstance(current_entry, ArchiveEntry) and is_material_sidecar_entry(current_entry):
                return current_entry
            for reference in self.current_archive_model_texture_references:
                resolved_entry = getattr(reference, "resolved_entry", None)
                if isinstance(resolved_entry, ArchiveEntry) and is_material_sidecar_entry(resolved_entry):
                    return resolved_entry
            if not isinstance(current_entry, ArchiveEntry):
                return None
            source_path = current_entry.path.replace("\\", "/").strip()
            source_stem = PurePosixPath(source_path).stem
            source_extension = str(current_entry.extension or "").strip().lower()
            candidate_basenames: List[str] = []
            if source_stem:
                candidate_basenames.append(f"{source_stem}.xml")
                if source_extension == ".pac":
                    candidate_basenames.append(f"{source_stem}.pac_xml")
                elif source_extension == ".pam":
                    candidate_basenames.extend([f"{source_stem}.pami", f"{source_stem}.pam_xml"])
                elif source_extension == ".pamlod":
                    candidate_basenames.extend([f"{source_stem}.pami", f"{source_stem}.pamlod_xml"])
            for basename in candidate_basenames:
                for candidate in self.archive_entries_by_basename.get(basename.lower(), ()):
                    if is_material_sidecar_entry(candidate):
                        return candidate
            return None

        def _material_sidecar_selection_candidates(self) -> List[ArchiveEntry]:
            candidates: List[ArchiveEntry] = []
            seen_paths: set[str] = set()

            def add(entry: Optional[ArchiveEntry]) -> None:
                if not isinstance(entry, ArchiveEntry) or not is_material_sidecar_entry(entry):
                    return
                normalized = entry.path.replace("\\", "/").strip().lower()
                if not normalized or normalized in seen_paths:
                    return
                seen_paths.add(normalized)
                candidates.append(entry)

            add(self._current_archive_entry())
            for reference in self.current_archive_model_texture_references:
                add(getattr(reference, "resolved_entry", None))
            add(self._current_or_related_material_sidecar_entry())
            return candidates

        def _choose_material_sidecar_entry(self, entries: Sequence[ArchiveEntry]) -> Optional[ArchiveEntry]:
            unique_entries: List[ArchiveEntry] = []
            seen_paths: set[str] = set()
            for entry in entries:
                normalized = entry.path.replace("\\", "/").strip().lower()
                if normalized and normalized not in seen_paths:
                    seen_paths.add(normalized)
                    unique_entries.append(entry)
            if not unique_entries:
                return None
            if len(unique_entries) == 1:
                return unique_entries[0]
            labels = [f"{entry.path} [{entry.package_label}]" for entry in unique_entries]
            selected, accepted = QInputDialog.getItem(
                self,
                "Choose Material Sidecar",
                "Material sidecar",
                labels,
                0,
                False,
            )
            if not accepted or not selected:
                return None
            selected_index = labels.index(selected)
            return unique_entries[selected_index]

        def _edit_current_archive_material_sidecar(self) -> None:
            entry = self._choose_material_sidecar_entry(self._material_sidecar_selection_candidates())
            if entry is None:
                self.set_status_message("No material sidecar is available for the current archive selection.", error=True)
                return
            self._open_material_sidecar_editor(entry)

        def _edit_selected_archive_material_sidecar_reference(self) -> None:
            selected_entries = self._resolved_archive_reference_entries(self._selected_archive_texture_references())
            entry = selected_entries[0] if len(selected_entries) == 1 else None
            if not isinstance(entry, ArchiveEntry) or not is_material_sidecar_entry(entry):
                self.set_status_message("Select one resolved material sidecar reference first.", error=True)
                return
            self._open_material_sidecar_editor(entry)

        @staticmethod
        def _decode_material_sidecar_bytes(data: bytes) -> str:
            decoded = try_decode_text_like_archive_data(data)
            if decoded is not None:
                return decoded
            return data.decode("utf-8", errors="replace")

        @staticmethod
        def _qcolor_from_material_value(value: str) -> QColor:
            text = str(value or "").strip()
            if re.fullmatch(r"#?[0-9a-fA-F]{6}(?:[0-9a-fA-F]{2})?", text):
                return QColor("#" + text.lstrip("#")[:6])
            numbers: List[float] = []
            for token in re.split(r"[\s,;]+", text):
                try:
                    numbers.append(float(token))
                except ValueError:
                    continue
                if len(numbers) >= 3:
                    break
            if len(numbers) >= 3:
                return QColor(
                    max(0, min(255, round(numbers[0] * 255))),
                    max(0, min(255, round(numbers[1] * 255))),
                    max(0, min(255, round(numbers[2] * 255))),
                )
            return QColor("#ffffff")

        def _prompt_material_sidecar_related_files(
            self,
            related_files: Sequence[MaterialSidecarRelatedFile],
            *,
            edited_entry: ArchiveEntry,
        ) -> Optional[Tuple[ArchiveEntry, ...]]:
            dialog = QDialog(self)
            dialog.setWindowTitle("Review Related Files")
            dialog.setModal(True)
            dialog.resize(920, 520)

            layout = QVBoxLayout(dialog)
            layout.setContentsMargins(12, 12, 12, 12)
            layout.setSpacing(8)
            intro = QLabel("Review related files to include with the edited material sidecar.")
            intro.setObjectName("HintLabel")
            intro.setWordWrap(True)
            layout.addWidget(intro)

            tree = QTreeWidget()
            tree.setColumnCount(5)
            tree.setHeaderLabels(["Include", "Confidence", "Reason", "Archive Path", "Package"])
            tree.setRootIsDecorated(False)
            tree.setAlternatingRowColors(True)
            tree.setSelectionMode(QAbstractItemView.NoSelection)
            tree.setUniformRowHeights(True)
            edited_item = QTreeWidgetItem(
                [
                    "",
                    "edited",
                    "Edited material sidecar; always included",
                    edited_entry.path,
                    edited_entry.package_label,
                ]
            )
            edited_item.setFlags((edited_item.flags() | Qt.ItemIsUserCheckable) & ~Qt.ItemIsEnabled)
            edited_item.setCheckState(0, Qt.Checked)
            edited_item.setData(0, Qt.UserRole, -1)
            tree.addTopLevelItem(edited_item)
            for index, related in enumerate(related_files):
                entry = related.entry
                item = QTreeWidgetItem(
                    [
                        "",
                        related.confidence,
                        related.reason,
                        entry.path,
                        entry.package_label,
                    ]
                )
                item.setFlags(item.flags() | Qt.ItemIsUserCheckable)
                item.setCheckState(0, Qt.Unchecked)
                item.setData(0, Qt.UserRole, index)
                tree.addTopLevelItem(item)
            header = tree.header()
            header.setStretchLastSection(False)
            header.setSectionResizeMode(0, QHeaderView.ResizeToContents)
            header.setSectionResizeMode(1, QHeaderView.ResizeToContents)
            header.setSectionResizeMode(2, QHeaderView.ResizeToContents)
            header.setSectionResizeMode(3, QHeaderView.Stretch)
            header.setSectionResizeMode(4, QHeaderView.ResizeToContents)
            layout.addWidget(tree, stretch=1)

            button_row = QHBoxLayout()
            select_all_button = QPushButton("Select All")
            select_none_button = QPushButton("Select None")
            button_row.addWidget(select_all_button)
            button_row.addWidget(select_none_button)
            button_row.addStretch(1)
            cancel_button = QPushButton("Cancel")
            continue_button = QPushButton("Continue")
            continue_button.setDefault(True)
            button_row.addWidget(cancel_button)
            button_row.addWidget(continue_button)
            layout.addLayout(button_row)
            cancel_button.clicked.connect(dialog.reject)
            continue_button.clicked.connect(dialog.accept)

            def _set_related_checks(state: Qt.CheckState) -> None:
                for row in range(tree.topLevelItemCount()):
                    item = tree.topLevelItem(row)
                    raw_index = item.data(0, Qt.UserRole)
                    try:
                        related_index = int(raw_index)
                    except (TypeError, ValueError):
                        related_index = -1
                    if related_index < 0:
                        item.setCheckState(0, Qt.Checked)
                    else:
                        item.setCheckState(0, state)

            select_all_button.clicked.connect(lambda _checked=False: _set_related_checks(Qt.Checked))
            select_none_button.clicked.connect(lambda _checked=False: _set_related_checks(Qt.Unchecked))

            if dialog.exec() != QDialog.Accepted:
                return None
            selected_entries: List[ArchiveEntry] = []
            for row in range(tree.topLevelItemCount()):
                item = tree.topLevelItem(row)
                if item.checkState(0) != Qt.Checked:
                    continue
                raw_index = item.data(0, Qt.UserRole)
                try:
                    related_index = int(raw_index)
                except (TypeError, ValueError):
                    continue
                if related_index < 0:
                    continue
                if 0 <= related_index < len(related_files):
                    selected_entries.append(related_files[related_index].entry)
            return tuple(selected_entries)

        def _material_sidecar_preview_model_candidate(
            self,
            entry: ArchiveEntry,
            sidecar_text: str,
        ) -> Optional[ArchiveEntry]:
            current_entry = self._current_archive_entry()
            candidates = detect_material_sidecar_preview_model_candidates(
                entry,
                sidecar_text=sidecar_text,
                current_entry=current_entry,
                references=tuple(self.current_archive_model_texture_references),
                archive_entries_by_basename=self.archive_entries_by_basename,
                archive_entries_by_normalized_path=self.archive_entries_by_normalized_path,
            )
            return candidates[0].entry if candidates else None

        def _material_sidecar_texture_resolution_warnings(self, sidecar_text: str) -> Tuple[str, ...]:
            warnings: List[str] = []
            rows = discover_material_sidecar_values(sidecar_text)
            for row in rows:
                if row.kind != "texture":
                    continue
                texture_path = str(row.value or "").replace("\\", "/").strip()
                if not texture_path:
                    continue
                normalized = normalize_texture_reference_for_sidecar_lookup(texture_path)
                basename = PurePosixPath(texture_path).name.lower()
                if normalized and self.archive_entries_by_normalized_path.get(normalized):
                    continue
                if basename and self.archive_entries_by_basename.get(basename):
                    continue
                warnings.append(f"Unresolved texture path: {texture_path}")
                if len(warnings) >= 4:
                    break
            return tuple(warnings)

        @staticmethod
        def _normalized_material_preview_label(value: object) -> str:
            return re.sub(r"[^a-z0-9]+", "", str(value or "").strip().lower())

        def _apply_material_sidecar_preview_overrides_to_model(
            self,
            preview_model: Optional[object],
            sidecar_text: str,
        ) -> Tuple[str, ...]:
            if not isinstance(preview_model, ModelPreviewData):
                return ()
            meshes = [
                mesh
                for mesh in (getattr(preview_model, "meshes", None) or [])
                if isinstance(mesh, ModelPreviewMesh)
            ]
            if not meshes:
                return ()
            overrides = discover_material_sidecar_preview_overrides(sidecar_text)
            if not overrides:
                return ()
            notes: List[str] = []
            applied_count = 0
            low_confidence_count = 0

            def apply_override(mesh: ModelPreviewMesh, override: object, *, low_confidence: bool) -> None:
                nonlocal applied_count, low_confidence_count
                tint_color = tuple(getattr(override, "tint_color", ()) or ())
                if len(tint_color) >= 3:
                    color = (
                        max(0.0, min(1.0, float(tint_color[0]))),
                        max(0.0, min(1.0, float(tint_color[1]))),
                        max(0.0, min(1.0, float(tint_color[2]))),
                    )
                    mesh.preview_color = color
                    mesh.preview_texture_tint = (
                        max(0.0, min(2.0, float(tint_color[0]))),
                        max(0.0, min(2.0, float(tint_color[1]))),
                        max(0.0, min(2.0, float(tint_color[2]))),
                    )
                brightness = max(0.1, min(3.0, float(getattr(override, "brightness", 1.0) or 1.0)))
                mesh.preview_texture_brightness = brightness
                uv_scale = max(0.05, min(64.0, float(getattr(override, "uv_scale", 1.0) or 1.0)))
                if abs(uv_scale - 1.0) > 1e-6:
                    mesh.preview_texture_uv_scale = (uv_scale, uv_scale)
                if low_confidence:
                    low_confidence_count += 1
                applied_count += 1
                mesh.preview_texture_approximation_note = "Edited material XML preview approximation."

            unused_overrides = list(overrides)
            for mesh in meshes:
                mesh_labels = {
                    self._normalized_material_preview_label(getattr(mesh, "material_name", "")),
                    self._normalized_material_preview_label(getattr(mesh, "texture_name", "")),
                    self._normalized_material_preview_label(getattr(mesh, "preview_sidecar_material_primitive", "")),
                }
                mesh_labels.discard("")
                matched_override = None
                for override in overrides:
                    override_label = self._normalized_material_preview_label(getattr(override, "group_label", ""))
                    if override_label and override_label in mesh_labels:
                        matched_override = override
                        break
                if matched_override is not None:
                    apply_override(mesh, matched_override, low_confidence=False)
                    if matched_override in unused_overrides:
                        unused_overrides.remove(matched_override)

            if applied_count <= 0:
                if len(overrides) == 1:
                    for mesh in meshes:
                        apply_override(mesh, overrides[0], low_confidence=False)
                else:
                    for mesh_index, mesh in enumerate(meshes):
                        override = overrides[min(mesh_index, len(overrides) - 1)]
                        apply_override(mesh, override, low_confidence=True)
            elif unused_overrides and len(meshes) == 1:
                apply_override(meshes[0], unused_overrides[0], low_confidence=True)

            if applied_count > 0:
                notes.append(f"Applied {applied_count:,} edited material preview approximation(s).")
            if low_confidence_count > 0:
                notes.append(f"{low_confidence_count:,} preview assignment(s) used low-confidence material matching.")
            if any("dye" in str(getattr(override, "reason", "") or "").lower() for override in overrides):
                notes.append("Dye and mask colors are approximated by the toolkit preview shader, not the exact game shader.")
            return tuple(notes)

        def _open_material_sidecar_editor(self, entry: ArchiveEntry) -> None:
            try:
                data, _decompressed, _note = read_archive_entry_data(entry)
                original_text = self._decode_material_sidecar_bytes(data)
            except Exception as exc:
                self.set_status_message(f"Could not read material sidecar: {exc}", error=True)
                return
            rows = discover_material_sidecar_values(original_text)
            if not rows:
                QMessageBox.information(
                    self,
                    "Material Values",
                    "No recognized material values were found in this sidecar.",
                )
                return

            dialog = QDialog(self)
            dialog.setWindowTitle(f"Edit Material Values - {entry.basename}")
            dialog.setModal(True)
            dialog.resize(1460, 760)
            layout = QVBoxLayout(dialog)
            layout.setContentsMargins(12, 12, 12, 12)
            layout.setSpacing(8)
            intro = QLabel(
                "Edit recognized material values only. Colors accept comma-separated RGB floats such as 0.1, 0.1, 0.1 or #RRGGBB."
            )
            intro.setObjectName("HintLabel")
            intro.setWordWrap(True)
            layout.addWidget(intro)

            content_splitter = QSplitter(Qt.Horizontal)
            editor_panel = QWidget()
            editor_layout = QVBoxLayout(editor_panel)
            editor_layout.setContentsMargins(0, 0, 0, 0)
            editor_layout.setSpacing(8)
            preview_panel = QWidget()
            preview_layout = QVBoxLayout(preview_panel)
            preview_layout.setContentsMargins(8, 0, 0, 0)
            preview_layout.setSpacing(8)

            tree = QTreeWidget()
            tree.setColumnCount(5)
            tree.setHeaderLabels(["Part / Material", "Kind", "Parameter", "Value", "Detail"])
            tree.setRootIsDecorated(False)
            tree.setAlternatingRowColors(True)
            tree.setUniformRowHeights(True)
            tree.setHorizontalScrollMode(QAbstractItemView.ScrollPerPixel)
            tree.setHorizontalScrollBarPolicy(Qt.ScrollBarAsNeeded)
            tree.setSelectionBehavior(QAbstractItemView.SelectRows)
            tree.setSelectionMode(QAbstractItemView.SingleSelection)
            for row in rows:
                item = QTreeWidgetItem(
                    [
                        row.group_label,
                        row.kind,
                        row.parameter_name,
                        row.value,
                        row.detail,
                    ]
                )
                item.setFlags(item.flags() & ~Qt.ItemIsEditable)
                item.setData(0, Qt.UserRole, row.row_id)
                item.setData(3, Qt.UserRole, row.value)
                item.setToolTip(0, row.group_label)
                item.setToolTip(2, row.parameter_name)
                item.setToolTip(3, row.value)
                item.setToolTip(4, row.detail)
                tree.addTopLevelItem(item)
            header = tree.header()
            header.setStretchLastSection(False)
            header.resizeSection(0, 190)
            header.resizeSection(1, 72)
            header.resizeSection(2, 210)
            header.resizeSection(3, 520)
            header.setSectionResizeMode(0, QHeaderView.Interactive)
            header.setSectionResizeMode(1, QHeaderView.ResizeToContents)
            header.setSectionResizeMode(2, QHeaderView.Interactive)
            header.setSectionResizeMode(3, QHeaderView.Interactive)
            header.setSectionResizeMode(4, QHeaderView.Stretch)
            editor_layout.addWidget(tree, stretch=1)

            selected_value_row = QGridLayout()
            selected_value_row.setHorizontalSpacing(8)
            selected_value_label = QLabel("Selected value")
            selected_value_edit = QLineEdit()
            selected_value_edit.setPlaceholderText("Select a material value row to edit it here.")
            selected_value_edit.setClearButtonEnabled(True)
            selected_value_edit.setToolTip("Colors accept comma-separated RGB floats such as 0.1, 0.1, 0.1 or #RRGGBB.")
            selected_value_row.addWidget(selected_value_label, 0, 0)
            selected_value_row.addWidget(selected_value_edit, 0, 1)
            selected_value_row.setColumnStretch(1, 1)
            editor_layout.addLayout(selected_value_row)
            selected_detail_label = QLabel("")
            selected_detail_label.setObjectName("HintLabel")
            selected_detail_label.setWordWrap(True)
            editor_layout.addWidget(selected_detail_label)

            preview_header_row = QHBoxLayout()
            show_preview_button = QPushButton("Show Preview")
            refresh_preview_button = QPushButton("Refresh Preview")
            material_preview_settings_button = QPushButton("3D Preview Settings...")
            material_preview_settings_button.setToolTip("Use the same global 3D preview settings as the Archive Preview and Mesh Replacement Alignment previews.")
            live_preview_checkbox = QCheckBox("Live Color Preview")
            live_preview_checkbox.setChecked(True)
            preview_header_row.addWidget(show_preview_button)
            preview_header_row.addWidget(refresh_preview_button)
            preview_header_row.addWidget(material_preview_settings_button)
            preview_header_row.addWidget(live_preview_checkbox)
            preview_header_row.addStretch(1)
            preview_layout.addLayout(preview_header_row)
            preview_status_label = QLabel("Preview has not been built yet.")
            preview_status_label.setObjectName("HintLabel")
            preview_status_label.setWordWrap(True)
            preview_layout.addWidget(preview_status_label)
            material_preview_widget = ModelPreviewWidget("Click Show Preview to build an approximate model preview.", theme_key=self.current_theme_key)
            material_preview_widget.setMinimumWidth(420)
            self._configure_model_preview_widget(material_preview_widget, apply_toggle_defaults=True)
            preview_layout.addWidget(material_preview_widget, stretch=1)
            content_splitter.addWidget(editor_panel)
            content_splitter.addWidget(preview_panel)
            content_splitter.setStretchFactor(0, 3)
            content_splitter.setStretchFactor(1, 2)
            content_splitter.setSizes([850, 560])
            layout.addWidget(content_splitter, stretch=1)

            button_row = QHBoxLayout()
            pick_color_button = QPushButton("Pick Color...")
            reset_button = QPushButton("Reset Selected")
            export_button = QPushButton("Export Edited Material Mod...")
            close_button = QPushButton("Close")
            button_row.addWidget(pick_color_button)
            button_row.addWidget(reset_button)
            button_row.addStretch(1)
            button_row.addWidget(export_button)
            button_row.addWidget(close_button)
            layout.addLayout(button_row)

            def _current_item() -> Optional[QTreeWidgetItem]:
                item = tree.currentItem()
                return item if item is not None and item.data(0, Qt.UserRole) else None

            syncing_selected_value = {"active": False}

            def _sync_selected_value_from_tree() -> None:
                item = _current_item()
                syncing_selected_value["active"] = True
                try:
                    selected_value_edit.setEnabled(item is not None)
                    selected_value_edit.setText(item.text(3) if item is not None else "")
                    selected_value_edit.setToolTip(item.text(3) if item is not None else "")
                    if item is not None:
                        selected_detail_label.setText(
                            f"Selected: {item.text(0)} | {item.text(2)} | {item.text(4)}"
                        )
                    else:
                        selected_detail_label.clear()
                finally:
                    syncing_selected_value["active"] = False

            def _sync_tree_from_selected_value(text: str) -> None:
                if syncing_selected_value["active"]:
                    return
                item = _current_item()
                if item is None:
                    return
                item.setText(3, str(text or ""))
                item.setToolTip(3, str(text or ""))

            def _handle_material_tree_item_changed(item: QTreeWidgetItem, column: int) -> None:
                if column == 3 and item is _current_item():
                    _sync_selected_value_from_tree()
                    _schedule_live_preview_for_item(item)

            def _pick_color() -> None:
                item = _current_item()
                if item is None or item.text(1) != "color":
                    return
                color = QColorDialog.getColor(
                    self._qcolor_from_material_value(item.text(3)),
                    dialog,
                    "Choose Material Color",
                )
                if color.isValid():
                    item.setText(3, color.name())
                    _sync_selected_value_from_tree()

            def _reset_selected() -> None:
                item = _current_item()
                if item is not None:
                    original_value = str(item.data(3, Qt.UserRole) or "")
                    item.setText(3, original_value)
                    _sync_selected_value_from_tree()

            row_kind_by_id = {row.row_id: row.kind for row in rows}
            preview_model_entry_state: Dict[str, object] = {"entry": None, "resolved": False}
            preview_status_label.setText("Preview model lookup will run after the editor opens.")
            show_preview_button.setEnabled(False)
            refresh_preview_button.setEnabled(False)

            def _resolve_material_preview_model_entry() -> None:
                preview_model_entry = self._material_sidecar_preview_model_candidate(entry, "")
                preview_model_entry_state["entry"] = preview_model_entry
                preview_model_entry_state["resolved"] = True
                if preview_model_entry is None:
                    preview_status_label.setText("No associated .pac, .pam, or .pamlod model was found for this sidecar.")
                    show_preview_button.setEnabled(False)
                    refresh_preview_button.setEnabled(False)
                    return
                preview_status_label.setText(f"Associated preview model: {preview_model_entry.path}")
                show_preview_button.setEnabled(True)
                refresh_preview_button.setEnabled(True)

            def _edited_values(kinds: Optional[set[str]] = None) -> Dict[str, str]:
                edited: Dict[str, str] = {}
                for index in range(tree.topLevelItemCount()):
                    item = tree.topLevelItem(index)
                    row_id = str(item.data(0, Qt.UserRole) or "")
                    if kinds is not None and row_kind_by_id.get(row_id) not in kinds:
                        continue
                    original_value = str(item.data(3, Qt.UserRole) or "")
                    current_value = item.text(3).strip()
                    if row_id and current_value != original_value:
                        edited[row_id] = current_value
                return edited

            def _sidecar_text_for_preview(*, include_texture_edits: bool) -> str:
                kinds = None if include_texture_edits else {"color", "float"}
                edited_values = _edited_values(kinds)
                if not edited_values:
                    return original_text
                return apply_material_sidecar_edits(original_text, edited_values).text

            live_preview_timer = QTimer(dialog)
            live_preview_timer.setSingleShot(True)
            live_preview_timer.setInterval(450)
            preview_generation = {"value": 0}

            def _start_material_preview_refresh(*, include_texture_edits: bool, live: bool = False) -> None:
                preview_model_entry = preview_model_entry_state.get("entry")
                if not bool(preview_model_entry_state.get("resolved")):
                    preview_status_label.setText("Preview model lookup is still pending.")
                    return
                if preview_model_entry is None:
                    preview_status_label.setText("No associated .pac, .pam, or .pamlod model was found for this sidecar.")
                    return
                if not isinstance(preview_model_entry, ArchiveEntry):
                    preview_status_label.setText("Preview model lookup returned an unexpected entry.")
                    return
                try:
                    preview_sidecar_text = _sidecar_text_for_preview(include_texture_edits=include_texture_edits)
                except Exception as exc:
                    preview_status_label.setText(f"Material edit cannot be previewed yet: {exc}")
                    return
                preview_generation["value"] += 1
                generation = preview_generation["value"]
                texconv_text = self.texconv_path_edit.text().strip()
                texconv_path = Path(texconv_text).expanduser() if texconv_text else None
                if texconv_path is not None and not texconv_path.is_file():
                    texconv_path = None
                companion_entry = self._find_archive_preview_companion_entry(preview_model_entry)
                preview_settings = self._current_model_preview_render_settings()
                preview_status_label.setText(
                    "Building approximate material preview..."
                    if texconv_path is not None
                    else "Building approximate material preview; texconv is not set, so DDS texture shading may be unavailable."
                )

                def _task(log: Callable[[str], None]) -> object:
                    log(f"Building material preview for {preview_model_entry.path} from {entry.path}...")
                    result = build_archive_preview_result(
                        texconv_path,
                        preview_model_entry,
                        companion_entry=companion_entry,
                        texture_entries_by_normalized_path=self.archive_entries_by_normalized_path,
                        texture_entries_by_basename=self.archive_entries_by_basename,
                        sidecar_entries_by_texture_path=self.archive_sidecar_entries_by_texture_path,
                        sidecar_entries_by_texture_basename=self.archive_sidecar_entries_by_texture_basename,
                        include_loose_preview_assets=False,
                        visible_texture_mode=preview_settings.visible_texture_mode,
                    )
                    preview_model = self._clone_archive_preview_model(result.preview_model, strip_images=True)
                    notes: List[str] = []
                    if isinstance(preview_model, ModelPreviewData):
                        parsed_bindings = _parse_archive_model_sidecar_texture_bindings(
                            preview_sidecar_text,
                            sidecar_path=entry.path,
                        )
                        if parsed_bindings and texconv_path is not None:
                            sidecar_texts_by_path: Dict[str, Tuple[str, ...]] = {}
                            sidecar_texts_by_basename: Dict[str, Tuple[str, ...]] = {}
                            for binding in parsed_bindings:
                                normalized_texture = normalize_texture_reference_for_sidecar_lookup(binding.texture_path)
                                if normalized_texture:
                                    sidecar_texts_by_path[normalized_texture] = (preview_sidecar_text,)
                                    texture_basename = PurePosixPath(normalized_texture).name.lower()
                                    if texture_basename:
                                        sidecar_texts_by_basename[texture_basename] = (preview_sidecar_text,)
                            notes.extend(
                                _attach_model_sidecar_texture_preview_paths(
                                    texconv_path,
                                    preview_model_entry,
                                    preview_model,
                                    parsed_mesh=None,
                                    sidecar_texture_bindings=parsed_bindings,
                                    visible_texture_mode=preview_settings.visible_texture_mode,
                                    texture_entries_by_normalized_path=self.archive_entries_by_normalized_path,
                                    texture_entries_by_basename=self.archive_entries_by_basename,
                                    sidecar_texts_by_normalized_path=sidecar_texts_by_path,
                                    sidecar_texts_by_basename=sidecar_texts_by_basename,
                                )
                            )
                        notes.extend(self._apply_material_sidecar_preview_overrides_to_model(preview_model, preview_sidecar_text))
                    warnings = list(self._material_sidecar_texture_resolution_warnings(preview_sidecar_text)) if include_texture_edits else []
                    if texconv_path is None:
                        warnings.append("texconv.exe is not configured, so texture-backed preview paths cannot be refreshed.")
                    return generation, dataclasses.replace(result, preview_model=preview_model), tuple(notes), tuple(warnings), bool(live)

                def _handle_complete(result: object) -> None:
                    if not isinstance(result, tuple) or len(result) != 5:
                        preview_status_label.setText("Material preview finished with an unexpected result payload.")
                        return
                    result_generation, preview_result, notes, warnings, was_live = result
                    if int(result_generation) != int(preview_generation["value"]) or not dialog.isVisible():
                        return
                    if not isinstance(preview_result, ArchivePreviewResult) or not isinstance(preview_result.preview_model, ModelPreviewData):
                        detail = str(getattr(preview_result, "detail_text", "") or "").strip() if isinstance(preview_result, ArchivePreviewResult) else ""
                        material_preview_widget.clear_model("No model preview available for this material sidecar.")
                        preview_status_label.setText(detail or "No model preview available for this material sidecar.")
                        return
                    result_with_images = self._attach_archive_preview_result_images(preview_result)
                    self._configure_model_preview_widget(material_preview_widget, apply_toggle_defaults=True)
                    material_preview_widget.set_model(result_with_images.preview_model)
                    if material_preview_widget.textures_available():
                        material_preview_widget.set_use_textures(True)
                    status_parts = ["Approximate sidecar preview"]
                    if was_live:
                        status_parts.append("live color/scalar refresh")
                    status_parts.extend(str(note) for note in notes if str(note or "").strip())
                    status_parts.extend(str(warning) for warning in warnings if str(warning or "").strip())
                    preview_status_label.setText("\n".join(status_parts))

                self._run_utility_task(
                    status_message=f"Building material preview for {entry.basename}...",
                    task=_task,
                    on_complete=_handle_complete,
                    show_archive_progress=True,
                )

            def _schedule_live_preview_for_item(item: Optional[QTreeWidgetItem]) -> None:
                if item is None or preview_model_entry_state.get("entry") is None or not live_preview_checkbox.isChecked():
                    return
                if item.text(1) not in {"color", "float"}:
                    preview_status_label.setText("Texture path edits refresh when you click Refresh Preview.")
                    return
                live_preview_timer.start()

            live_preview_timer.timeout.connect(lambda: _start_material_preview_refresh(include_texture_edits=False, live=True))

            def _export() -> None:
                edited_values = _edited_values()
                if not edited_values:
                    QMessageBox.information(dialog, "No Changes", "Change at least one material value before exporting.")
                    return
                try:
                    edit_result = apply_material_sidecar_edits(original_text, edited_values)
                except Exception as exc:
                    QMessageBox.warning(dialog, "Material Edit Failed", str(exc))
                    return
                related_files = detect_material_sidecar_related_files(
                    entry,
                    references=tuple(self.current_archive_model_texture_references),
                    archive_entries_by_basename=self.archive_entries_by_basename,
                )
                selected_related_entries = self._prompt_material_sidecar_related_files(
                    related_files,
                    edited_entry=entry,
                )
                if selected_related_entries is None:
                    return
                target = self._collect_archive_mod_ready_export_target(
                    browse_title="Export Edited Material Mod",
                    prompt_for_metadata=True,
                    dialog_title="Export Edited Material Mod",
                )
                if target is None:
                    return
                export_root, package_info, create_no_encrypt_file, _include_related_files, export_options = target

                def _task(log: Callable[[str], None]) -> object:
                    return export_material_sidecar_mod_package(
                        edited_entry=entry,
                        edited_text=edit_result.text,
                        related_entries=selected_related_entries,
                        parent_root=export_root,
                        package_info=package_info,
                        export_options=export_options,
                        create_no_encrypt_file=create_no_encrypt_file,
                        read_entry_bytes=lambda archive_entry: read_archive_entry_data(archive_entry)[0],
                        on_log=log,
                    )

                def _handle_complete(result: object) -> None:
                    package_root = getattr(result, "package_root", None)
                    if not isinstance(package_root, Path):
                        self.set_status_message("Material mod export finished with an unexpected result payload.", error=True)
                        return
                    QMessageBox.information(
                        dialog,
                        "Export Complete",
                        f"Exported edited material mod:\n{package_root}",
                    )
                    self.set_status_message(f"Exported edited material mod to {package_root}.")

                self._run_utility_task(
                    status_message=f"Exporting edited material mod for {entry.basename}...",
                    task=_task,
                    on_complete=_handle_complete,
                    show_archive_progress=True,
                )

            pick_color_button.clicked.connect(_pick_color)
            reset_button.clicked.connect(_reset_selected)
            show_preview_button.clicked.connect(lambda _checked=False: _start_material_preview_refresh(include_texture_edits=True, live=False))
            refresh_preview_button.clicked.connect(lambda _checked=False: _start_material_preview_refresh(include_texture_edits=True, live=False))
            material_preview_settings_button.clicked.connect(
                lambda _checked=False, parent_dialog=dialog: self._open_modal_model_preview_settings_dialog(parent_dialog)
            )
            export_button.clicked.connect(_export)
            close_button.clicked.connect(dialog.accept)
            tree.currentItemChanged.connect(lambda _current, _previous: _sync_selected_value_from_tree())
            tree.itemChanged.connect(_handle_material_tree_item_changed)
            selected_value_edit.textEdited.connect(_sync_tree_from_selected_value)
            _sync_selected_value_from_tree()
            QTimer.singleShot(0, _resolve_material_preview_model_entry)
            dialog.exec()

        @staticmethod
        def _preview_slot_label(slot: str) -> str:
            normalized_slot = str(slot or "").strip().lower()
            return {
                "base": "Base",
                "normal": "Normal",
                "material": "Material",
                "height": "Height",
            }.get(normalized_slot, normalized_slot.title() or "Preview")

        def _build_local_dds_preview_override_path(
            self,
            source_path: Path,
            *,
            texconv_path: Optional[Path] = None,
        ) -> str:
            resolved_texconv_path = texconv_path
            if resolved_texconv_path is None:
                texconv_text = self.texconv_path_edit.text().strip()
                resolved_texconv_path = Path(texconv_text).expanduser() if texconv_text else None
            if resolved_texconv_path is None or not resolved_texconv_path.is_file():
                raise FileNotFoundError("Set a valid texconv.exe path before previewing an imported DDS.")
            resolved_source = source_path.expanduser().resolve()
            if not resolved_source.is_file():
                raise FileNotFoundError(f"Imported DDS was not found: {resolved_source}")
            dds_info = parse_dds(resolved_source)
            preview_path = ensure_dds_display_preview_png(
                resolved_texconv_path.resolve(),
                resolved_source,
                dds_info=dds_info,
            )
            return str(preview_path)

        def _apply_archive_entry_dds_preview_to_model(
            self,
            preview_model: Optional[object],
            *,
            slot: str,
            preview_path: str,
            texture_name: str,
            semantic_reference_path: str,
        ) -> bool:
            normalized_slot = str(slot or "").strip().lower()
            if normalized_slot not in {"base", "normal", "material", "height"}:
                return False
            preview_path_text = str(preview_path or "").strip()
            texture_name_text = str(texture_name or "").strip()
            if not preview_path_text or not isinstance(preview_model, ModelPreviewData):
                return False
            meshes = [
                mesh
                for mesh in (getattr(preview_model, "meshes", None) or [])
                if isinstance(mesh, ModelPreviewMesh)
            ]
            if not meshes:
                return False

            texture_type, semantic_subtype, _confidence, packed_channels = _resolve_model_texture_semantic_details(
                semantic_reference_path,
            )
            packed_channels_tuple = tuple(
                str(channel or "").strip().lower()
                for channel in packed_channels
                if str(channel or "").strip()
            )
            changed = False
            for mesh in meshes:
                if normalized_slot == "base":
                    if str(getattr(mesh, "preview_texture_path", "") or "").strip() != preview_path_text:
                        mesh.preview_texture_path = preview_path_text
                        mesh.preview_texture_image = None
                        changed = True
                    if str(getattr(mesh, "texture_name", "") or "").strip() != texture_name_text:
                        mesh.texture_name = texture_name_text
                        changed = True
                    if getattr(mesh, "preview_texture_flip_vertical", None) is not False:
                        mesh.preview_texture_flip_vertical = False
                        changed = True
                    continue
                if normalized_slot == "normal":
                    material_name = str(getattr(mesh, "material_name", "") or "").strip()
                    base_texture_name = str(getattr(mesh, "texture_name", "") or "").strip()
                    normal_strength = _infer_model_preview_normal_strength(
                        base_texture_path=base_texture_name,
                        normal_texture_path=semantic_reference_path,
                        material_name=material_name,
                        prefer_stronger=True,
                    )
                    if str(getattr(mesh, "preview_normal_texture_path", "") or "").strip() != preview_path_text:
                        mesh.preview_normal_texture_path = preview_path_text
                        mesh.preview_normal_texture_image = None
                        changed = True
                    if str(getattr(mesh, "preview_normal_texture_name", "") or "").strip() != texture_name_text:
                        mesh.preview_normal_texture_name = texture_name_text
                        changed = True
                    if abs(float(getattr(mesh, "preview_normal_texture_strength", 0.0) or 0.0) - float(normal_strength)) > 1e-6:
                        mesh.preview_normal_texture_strength = float(normal_strength)
                        changed = True
                    continue
                if normalized_slot == "material":
                    if str(getattr(mesh, "preview_material_texture_path", "") or "").strip() != preview_path_text:
                        mesh.preview_material_texture_path = preview_path_text
                        mesh.preview_material_texture_image = None
                        changed = True
                    if str(getattr(mesh, "preview_material_texture_name", "") or "").strip() != texture_name_text:
                        mesh.preview_material_texture_name = texture_name_text
                        changed = True
                    if str(getattr(mesh, "preview_material_texture_type", "") or "").strip().lower() != str(texture_type or "").strip().lower():
                        mesh.preview_material_texture_type = str(texture_type or "").strip().lower()
                        changed = True
                    if str(getattr(mesh, "preview_material_texture_subtype", "") or "").strip().lower() != str(semantic_subtype or "").strip().lower():
                        mesh.preview_material_texture_subtype = str(semantic_subtype or "").strip().lower()
                        changed = True
                    if tuple(
                        str(channel or "").strip().lower()
                        for channel in (getattr(mesh, "preview_material_texture_packed_channels", ()) or ())
                        if str(channel or "").strip()
                    ) != packed_channels_tuple:
                        mesh.preview_material_texture_packed_channels = packed_channels_tuple
                        changed = True
                    continue
                if str(getattr(mesh, "preview_height_texture_path", "") or "").strip() != preview_path_text:
                    mesh.preview_height_texture_path = preview_path_text
                    mesh.preview_height_texture_image = None
                    changed = True
                if str(getattr(mesh, "preview_height_texture_name", "") or "").strip() != texture_name_text:
                    mesh.preview_height_texture_name = texture_name_text
                    changed = True
            return changed

        def _build_archive_mesh_dds_import_preview_result(
            self,
            entry: ArchiveEntry,
            source_path: Path,
            slot: str,
            *,
            texconv_path: Optional[Path],
            companion_entry: Optional[ArchiveEntry],
            visible_texture_mode: str,
        ) -> ArchivePreviewResult:
            normalized_slot = str(slot or "").strip().lower()
            slot_label = self._preview_slot_label(normalized_slot)
            resolved_source_path = source_path.expanduser().resolve()
            preview_result = build_archive_preview_result(
                texconv_path,
                entry,
                companion_entry=companion_entry,
                texture_entries_by_normalized_path=self.archive_entries_by_normalized_path,
                texture_entries_by_basename=self.archive_entries_by_basename,
                sidecar_entries_by_texture_path=self.archive_sidecar_entries_by_texture_path,
                sidecar_entries_by_texture_basename=self.archive_sidecar_entries_by_texture_basename,
                visible_texture_mode=visible_texture_mode,
            )
            preview_model = self._clone_archive_preview_model(preview_result.preview_model, strip_images=False)
            if not isinstance(preview_model, ModelPreviewData) or not getattr(preview_model, "meshes", None):
                failure_reason = (
                    str(preview_result.warning_text or "").strip()
                    or str(preview_result.detail_text or "").strip()
                    or "No renderable model preview is available."
                )
                raise RuntimeError(f"Could not prepare a model preview for {entry.basename}: {failure_reason}")

            preview_path = self._build_local_dds_preview_override_path(
                resolved_source_path,
                texconv_path=texconv_path,
            )
            applied = self._apply_archive_entry_dds_preview_to_model(
                preview_model,
                slot=normalized_slot,
                preview_path=preview_path,
                texture_name=resolved_source_path.name,
                semantic_reference_path=str(resolved_source_path),
            )
            if not applied:
                raise RuntimeError(
                    f"Could not apply the imported DDS to the {slot_label.lower()} preview slot for {entry.basename}."
                )

            detail_text = "\n\n".join(
                part
                for part in (
                    str(preview_result.detail_text or "").strip(),
                    "\n".join(
                        [
                            "DDS Import Preview:",
                            f"Selected DDS: {resolved_source_path.name}",
                            f"Selected slot: {slot_label}",
                        ]
                    ),
                )
                if part
            )
            warning_text = "This DDS preview has not been written back to the game archives yet."
            existing_warning = str(preview_result.warning_text or "").strip()
            if existing_warning:
                warning_text = f"{warning_text}\n{existing_warning}"
            return dataclasses.replace(
                preview_result,
                detail_text=detail_text,
                preview_model=preview_model,
                preferred_view="model",
                warning_badge="Import preview",
                warning_text=warning_text,
                loose_file_path="",
                loose_preview_image_path="",
                loose_preview_image=None,
                loose_preview_media_path="",
                loose_preview_media_kind="",
                loose_preview_title="",
                loose_preview_metadata_summary="",
                loose_preview_detail_text="",
            )

        def _show_archive_dds_import_preview_result(
            self,
            preview_result: ArchivePreviewResult,
            *,
            enable_high_quality: bool,
        ) -> None:
            result_with_images = self._attach_archive_preview_result_images(preview_result)
            self.archive_preview_requested_loose = False
            self.current_archive_preview_result = result_with_images
            self._show_archive_preview_result(result_with_images, use_loose=False)
            if (
                result_with_images.preview_model is None
                or self.archive_preview_stack.currentWidget() is not self.archive_model_preview
            ):
                return
            if self.archive_model_preview.textures_available():
                self.archive_model_preview.set_use_textures(True)
                if enable_high_quality:
                    self.archive_model_preview.set_high_quality_textures(True)
            self._sync_current_archive_preview_model_from_widget()
            self._sync_archive_model_preview_debug_controls(self._archive_model_preview_controls_target())
            self._refresh_archive_preview_details_text()

        def _start_archive_mesh_dds_import_preview(self, entry: ArchiveEntry) -> None:
            source_path, _selected = QFileDialog.getOpenFileName(
                self,
                "Select DDS File",
                str(self.settings_file_path.parent),
                "DDS (*.dds)",
            )
            if not source_path:
                return
            slot_labels = ["Base", "Normal", "Material", "Height"]
            selected_slot_label, accepted = QInputDialog.getItem(
                self,
                "Preview Slot",
                "Apply the imported DDS to which preview slot?",
                slot_labels,
                0,
                False,
            )
            if not accepted or not selected_slot_label:
                return

            resolved_source_path = Path(source_path).expanduser().resolve()
            normalized_slot = str(selected_slot_label or "").strip().lower()
            texconv_text = self.texconv_path_edit.text().strip()
            texconv_path = Path(texconv_text).expanduser() if texconv_text else None
            companion_entry = self._find_archive_preview_companion_entry(entry)
            preview_settings = self._current_model_preview_render_settings()

            def _task(log: Callable[[str], None]) -> ArchivePreviewResult:
                log(f"Preparing DDS import preview for {entry.path} using {resolved_source_path.name}...")
                return self._build_archive_mesh_dds_import_preview_result(
                    entry,
                    resolved_source_path,
                    normalized_slot,
                    texconv_path=texconv_path,
                    companion_entry=companion_entry,
                    visible_texture_mode=preview_settings.visible_texture_mode,
                )

            def _handle_complete(result: object) -> None:
                if not isinstance(result, ArchivePreviewResult):
                    self.set_status_message("DDS import preview finished with an unexpected result payload.", error=True)
                    return
                self._show_archive_dds_import_preview_result(
                    result,
                    enable_high_quality=normalized_slot in {"normal", "material", "height"},
                )
                self.set_status_message(
                    f"Prepared {self._preview_slot_label(normalized_slot).lower()} DDS import preview for {entry.basename}.",
                    error=False,
                )

            self._run_utility_task(
                status_message=f"Preparing DDS import preview for {entry.basename}...",
                task=_task,
                on_complete=_handle_complete,
                show_archive_progress=True,
            )

        def _current_archive_related_references_for_entry(
            self,
            entry: ArchiveEntry,
        ) -> Tuple[ArchiveModelTextureReference, ...]:
            current_entry = self._current_archive_entry()
            if current_entry is None:
                return ()
            current_path = current_entry.path.replace("\\", "/").strip().lower()
            target_path = entry.path.replace("\\", "/").strip().lower()
            if current_path != target_path:
                return ()
            return tuple(self.current_archive_model_texture_references)

        def _archive_reference_export_filter(self, entry: ArchiveEntry) -> str:
            extension = str(entry.extension or "").strip().lower()
            if extension == ".dds":
                return "DDS (*.dds)"
            if extension == ".xml":
                return "XML (*.xml);;All Files (*)"
            if extension == ".pami":
                return "PAMI (*.pami);;All Files (*)"
            if extension == ".json":
                return "JSON (*.json);;All Files (*)"
            if extension:
                return f"{extension.upper()} (*{extension});;All Files (*)"
            return "All Files (*)"

        def _export_archive_reference_entry(self, entry: ArchiveEntry, *, title: str = "Export Referenced File") -> None:
            default_dir = self.settings_file_path.parent / "archive_related_export"
            default_target = default_dir / entry.basename
            output_path, _selected = QFileDialog.getSaveFileName(
                self,
                title,
                str(default_target),
                self._archive_reference_export_filter(entry),
            )
            if not output_path:
                return

            def _task(log: Callable[[str], None]) -> Path:
                log(f"Exporting referenced file for {entry.path}...")
                source_path, _note = ensure_archive_preview_source(entry)
                target_path = Path(output_path).expanduser()
                target_path.parent.mkdir(parents=True, exist_ok=True)
                shutil.copy2(source_path, target_path)
                return target_path.resolve()

            def _handle_complete(result: object) -> None:
                if not isinstance(result, Path):
                    self.set_status_message("Referenced file export finished with an unexpected result payload.", error=True)
                    return
                QMessageBox.information(self, "Export Complete", f"Exported file:\n{result}")
                self.set_status_message(f"Exported {entry.basename}.")

            self._run_utility_task(
                status_message=f"Exporting {entry.basename}...",
                task=_task,
                on_complete=_handle_complete,
                show_archive_progress=True,
            )

        def _export_archive_reference_entries_to_folder(
            self,
            entries: Sequence[ArchiveEntry],
            *,
            title: str,
        ) -> None:
            unique_entries: List[ArchiveEntry] = []
            seen_paths: set[str] = set()
            for entry in entries:
                normalized_path = entry.path.replace("\\", "/").strip().lower()
                if not normalized_path or normalized_path in seen_paths:
                    continue
                seen_paths.add(normalized_path)
                unique_entries.append(entry)
            if not unique_entries:
                self.set_status_message("No resolved referenced files are available to export.", error=True)
                return

            default_dir = self.settings_file_path.parent / "archive_related_export"
            output_dir = QFileDialog.getExistingDirectory(
                self,
                title,
                str(default_dir),
            )
            if not output_dir:
                return

            def _task(log: Callable[[str], None]) -> List[Path]:
                exported_root = Path(output_dir).expanduser()
                exported_paths: List[Path] = []
                for related_entry in unique_entries:
                    source_path, _note = ensure_archive_preview_source(related_entry)
                    target_path = exported_root.joinpath(*PurePosixPath(related_entry.path.replace("\\", "/")).parts)
                    target_path.parent.mkdir(parents=True, exist_ok=True)
                    log(f"Exporting referenced file: {related_entry.path}")
                    shutil.copy2(source_path, target_path)
                    exported_paths.append(target_path.resolve())
                return exported_paths

            def _handle_complete(result: object) -> None:
                if not isinstance(result, list) or not all(isinstance(path, Path) for path in result):
                    self.set_status_message("Referenced-file export finished with an unexpected result payload.", error=True)
                    return
                QMessageBox.information(
                    self,
                    "Export Complete",
                    f"Exported {len(result)} referenced file(s) into:\n{Path(output_dir).expanduser()}",
                )
                self.set_status_message(f"Exported {len(result)} referenced file(s).")

            self._run_utility_task(
                status_message=f"Exporting {len(unique_entries)} referenced file(s)...",
                task=_task,
                on_complete=_handle_complete,
                show_archive_progress=True,
            )

        def _prompt_archive_reference_selection(
            self,
            *,
            title: str,
            intro_text: str,
            references: Sequence[ArchiveModelTextureReference],
            confirm_button_text: str = "Continue",
        ) -> Optional[Tuple[ArchiveEntry, ...]]:
            resolved_references: List[ArchiveModelTextureReference] = []
            seen_paths: set[str] = set()
            for reference in references:
                resolved_entry = getattr(reference, "resolved_entry", None)
                if not isinstance(resolved_entry, ArchiveEntry):
                    continue
                normalized_path = resolved_entry.path.replace("\\", "/").strip().lower()
                if not normalized_path or normalized_path in seen_paths:
                    continue
                seen_paths.add(normalized_path)
                resolved_references.append(reference)
            if not resolved_references:
                return ()

            dialog = QDialog(self)
            dialog.setWindowTitle(title)
            dialog.setModal(True)
            dialog.resize(900, 520)

            layout = QVBoxLayout(dialog)
            layout.setContentsMargins(12, 12, 12, 12)
            layout.setSpacing(8)

            intro_label = QLabel(intro_text)
            intro_label.setWordWrap(True)
            intro_label.setObjectName("HintLabel")
            layout.addWidget(intro_label)

            tree = QTreeWidget()
            tree.setColumnCount(5)
            tree.setHeaderLabels(["Include", "Type", "Semantic", "Archive Path", "Package"])
            tree.setRootIsDecorated(False)
            tree.setAlternatingRowColors(True)
            tree.setSelectionMode(QAbstractItemView.NoSelection)
            tree.setUniformRowHeights(True)
            tree.setHorizontalScrollMode(QAbstractItemView.ScrollPerPixel)
            header = tree.header()
            header.setStretchLastSection(False)
            header.setSectionResizeMode(0, QHeaderView.ResizeToContents)
            header.setSectionResizeMode(1, QHeaderView.ResizeToContents)
            header.setSectionResizeMode(2, QHeaderView.ResizeToContents)
            header.setSectionResizeMode(3, QHeaderView.Stretch)
            header.setSectionResizeMode(4, QHeaderView.ResizeToContents)

            def _reference_type_label(reference: ArchiveModelTextureReference) -> str:
                relation_group = str(getattr(reference, "relation_group", "") or "").strip().lower()
                resolved_entry = getattr(reference, "resolved_entry", None)
                extension = str(getattr(resolved_entry, "extension", "") or "").strip().lower()
                reference_kind = str(getattr(reference, "reference_kind", "") or "").strip().lower()
                if relation_group == "textures" or reference_kind == "texture" or extension == ".dds":
                    return "Texture"
                if relation_group == "material sidecars" or extension in {".xml", ".pami", ".pac_xml", ".pam_xml", ".pamlod_xml"}:
                    return "Material Sidecar"
                if relation_group == "mesh / model" or reference_kind in {"mesh", "lod"} or extension in {".pac", ".pam", ".pamlod"}:
                    return "Mesh / Model"
                if relation_group == "skeleton / rig" or extension == ".pab":
                    return "Skeleton / Rig"
                if relation_group == "animation / motion" or extension in {".hkx", ".motionblending", ".paa", ".pae", ".paem"}:
                    return "Animation / Motion"
                if extension:
                    return extension.lstrip(".").upper()
                return "Related File"

            for index, reference in enumerate(resolved_references):
                resolved_entry = reference.resolved_entry
                if not isinstance(resolved_entry, ArchiveEntry):
                    continue
                label = str(getattr(reference, "reference_name", "") or "").strip() or resolved_entry.basename
                type_label = _reference_type_label(reference)
                item = QTreeWidgetItem(
                    [
                        label,
                        type_label,
                        str(getattr(reference, "semantic_label", "") or "").strip() or "-",
                        resolved_entry.path,
                        resolved_entry.package_label,
                    ]
                )
                item.setFlags(item.flags() | Qt.ItemIsUserCheckable | Qt.ItemIsEnabled)
                item.setCheckState(0, Qt.Checked)
                item.setData(0, Qt.UserRole, index)
                item.setToolTip(3, resolved_entry.path)
                tree.addTopLevelItem(item)

            layout.addWidget(tree, stretch=1)

            controls_row = QHBoxLayout()
            controls_row.setSpacing(8)
            select_all_button = QPushButton("Select All")
            select_none_button = QPushButton("Select None")
            controls_row.addWidget(select_all_button)
            controls_row.addWidget(select_none_button)
            controls_row.addStretch(1)
            cancel_button = QPushButton("Cancel")
            confirm_button = QPushButton(confirm_button_text)
            confirm_button.setDefault(True)
            controls_row.addWidget(cancel_button)
            controls_row.addWidget(confirm_button)
            layout.addLayout(controls_row)

            result: List[ArchiveEntry] = []

            def _set_all(check_state: Qt.CheckState) -> None:
                for row_index in range(tree.topLevelItemCount()):
                    item = tree.topLevelItem(row_index)
                    if item is not None:
                        item.setCheckState(0, check_state)

            def _accept() -> None:
                selected_entries: List[ArchiveEntry] = []
                for row_index in range(tree.topLevelItemCount()):
                    item = tree.topLevelItem(row_index)
                    if item is None or item.checkState(0) != Qt.Checked:
                        continue
                    raw_index = item.data(0, Qt.UserRole)
                    try:
                        index = int(raw_index)
                    except (TypeError, ValueError):
                        continue
                    if 0 <= index < len(resolved_references):
                        resolved_entry = getattr(resolved_references[index], "resolved_entry", None)
                        if isinstance(resolved_entry, ArchiveEntry):
                            selected_entries.append(resolved_entry)
                result[:] = selected_entries
                dialog.accept()

            select_all_button.clicked.connect(lambda: _set_all(Qt.Checked))
            select_none_button.clicked.connect(lambda: _set_all(Qt.Unchecked))
            cancel_button.clicked.connect(dialog.reject)
            confirm_button.clicked.connect(_accept)

            if dialog.exec() != QDialog.Accepted:
                return None
            return tuple(result)

        def _show_archive_reference_preview_dialog(
            self,
            entry: ArchiveEntry,
            result: ArchivePreviewResult,
        ) -> None:
            dialog = QDialog(self)
            dialog.setWindowTitle(f"Referenced File Preview - {entry.basename}")
            dialog.setModal(True)
            dialog.resize(1040, 760)

            layout = QVBoxLayout(dialog)
            layout.setContentsMargins(12, 12, 12, 12)
            layout.setSpacing(8)

            title_label = QLabel(result.title or entry.basename)
            title_label.setObjectName("SectionTitle")
            layout.addWidget(title_label)

            meta_label = QLabel(result.metadata_summary or build_archive_entry_metadata_summary(entry))
            meta_label.setWordWrap(True)
            meta_label.setObjectName("HintLabel")
            layout.addWidget(meta_label)

            action_row = QHBoxLayout()
            action_row.setSpacing(8)
            export_button = QPushButton("Export DDS..." if entry.extension == ".dds" else "Export...")
            action_row.addWidget(export_button)
            open_in_editor_button: Optional[QPushButton] = None
            if entry.extension == ".dds":
                open_in_editor_button = QPushButton("Open In Texture Editor...")
                action_row.addWidget(open_in_editor_button)
            preview_dialog_settings_button = QPushButton("3D Preview Settings...")
            preview_dialog_settings_button.setToolTip("Open the global 3D preview settings used by every model preview window.")
            preview_dialog_settings_button.setVisible(result.preferred_view == "model" and result.preview_model is not None)
            action_row.addWidget(preview_dialog_settings_button)
            action_row.addStretch(1)
            close_button = QPushButton("Close")
            close_button.setDefault(True)
            action_row.addWidget(close_button)
            layout.addLayout(action_row)

            preview_tabs = QTabWidget()
            preview_stack = QStackedWidget()
            preview_label = PreviewLabel("No image preview available.")
            preview_scroll = PreviewScrollArea()
            preview_scroll.setWidgetResizable(False)
            preview_scroll.setAlignment(Qt.AlignCenter)
            preview_scroll.setWidget(preview_label)
            preview_label.attach_scroll_area(preview_scroll)
            preview_text_edit = CodePreviewEditor(theme_key=self.current_theme_key)
            preview_text_edit.document().setMaximumBlockCount(5000)
            preview_info_edit = QPlainTextEdit()
            preview_info_edit.setReadOnly(True)
            preview_info_edit.document().setMaximumBlockCount(2000)
            dialog_font = build_monospace_font(self.settings)
            dialog_highlight_style = read_log_text_style(self.settings)
            preview_text_edit.apply_font_preferences(dialog_font, preserve_size=False)
            preview_text_edit.set_highlight_style(dialog_highlight_style)
            preview_info_edit.setFont(dialog_font)
            preview_info_edit.document().setDefaultFont(dialog_font)
            preview_model = ModelPreviewWidget("No model preview available.", theme_key=self.current_theme_key)
            self._configure_model_preview_widget(preview_model, apply_toggle_defaults=True)
            preview_media = MediaPreviewWidget("No media preview available.", theme_key=self.current_theme_key)
            preview_stack.addWidget(preview_scroll)
            preview_stack.addWidget(preview_model)
            preview_stack.addWidget(preview_media)
            preview_stack.addWidget(preview_text_edit)
            preview_stack.addWidget(preview_info_edit)

            preview_tab = QWidget()
            preview_tab_layout = QVBoxLayout(preview_tab)
            preview_tab_layout.setContentsMargins(0, 0, 0, 0)
            preview_tab_layout.setSpacing(0)
            preview_tab_layout.addWidget(preview_stack)

            details_edit = ArchiveDetailsEditor(
                theme_key=self.current_theme_key,
                highlight_style=dialog_highlight_style,
            )
            details_edit.document().setMaximumBlockCount(2000)
            details_edit.apply_font_preferences(dialog_font, preserve_size=False)
            base_detail_text = result.detail_text or result.metadata_summary or "No details available."

            def _update_preview_dialog_details(_debug_text: str = "") -> None:
                details_edit.setPlainText(
                    self._compose_model_preview_detail_text(
                        base_detail_text,
                        preview_model.debug_details_text(),
                    )
                )

            preview_model.debug_details_changed.connect(_update_preview_dialog_details)
            _update_preview_dialog_details()

            details_tab = QWidget()
            details_tab_layout = QVBoxLayout(details_tab)
            details_tab_layout.setContentsMargins(0, 0, 0, 0)
            details_tab_layout.setSpacing(0)
            details_tab_layout.addWidget(details_edit)

            preview_tabs.addTab(preview_tab, "Preview")
            preview_tabs.addTab(details_tab, "Details")
            layout.addWidget(preview_tabs, stretch=1)

            preferred_view = result.preferred_view
            if preferred_view == "image" and (result.preview_image is not None or result.preview_image_path):
                if result.preview_image is not None:
                    preview_label.set_preview_image(result.preview_image, result.title or entry.basename)
                else:
                    preview_label.set_preview_image_path(result.preview_image_path, result.title or entry.basename)
                preview_media.clear_media("No media preview available.")
                preview_model.clear_model("No model preview available.")
                preview_stack.setCurrentWidget(preview_scroll)
            elif preferred_view == "model" and result.preview_model is not None:
                preview_model.set_model(result.preview_model)
                preview_label.clear_preview("No image preview available.")
                preview_media.clear_media("No media preview available.")
                preview_stack.setCurrentWidget(preview_model)
            elif preferred_view == "media" and result.preview_media_path:
                preview_label.clear_preview("No image preview available.")
                preview_model.clear_model("No model preview available.")
                preview_media.set_media(
                    result.preview_media_path,
                    media_kind=result.preview_media_kind,
                    detail_text=result.detail_text or result.metadata_summary,
                )
                preview_stack.setCurrentWidget(preview_media)
            elif preferred_view == "text":
                preview_text = result.preview_text or "No text preview available."
                preview_text_edit.set_language_for_extension(
                    self._archive_preview_text_language_extension_for_entry(entry, preview_text)
                )
                preview_text_edit.setPlainText(preview_text)
                preview_label.clear_preview("No image preview available.")
                preview_model.clear_model("No model preview available.")
                preview_media.clear_media("No media preview available.")
                preview_stack.setCurrentWidget(preview_text_edit)
            else:
                preview_info_edit.setPlainText(result.detail_text or result.metadata_summary or "No preview available.")
                preview_label.clear_preview("No image preview available.")
                preview_model.clear_model("No model preview available.")
                preview_media.clear_media("No media preview available.")
                preview_stack.setCurrentWidget(preview_info_edit)

            export_button.clicked.connect(
                lambda _checked=False, current_entry=entry: self._export_archive_reference_entry(current_entry)
            )
            if open_in_editor_button is not None:
                open_in_editor_button.clicked.connect(
                    lambda _checked=False, current_entry=entry: self._open_archive_entry_in_texture_editor(current_entry)
                )
            preview_dialog_settings_button.clicked.connect(
                lambda _checked=False, parent_dialog=dialog: self._open_modal_model_preview_settings_dialog(parent_dialog)
            )
            close_button.clicked.connect(dialog.accept)
            dialog.exec()

        def _update_archive_texture_reference_action_controls(self) -> None:
            selected_references = self._selected_archive_texture_references()
            selected_entries = self._resolved_archive_reference_entries(selected_references)
            all_entries = self._resolved_archive_reference_entries(self.current_archive_model_texture_references)
            single_selected_entry = selected_entries[0] if len(selected_entries) == 1 else None
            can_open = isinstance(single_selected_entry, ArchiveEntry)
            self.archive_texture_open_button.setEnabled(can_open)
            self.archive_texture_export_button.setEnabled(bool(selected_entries))
            self.archive_texture_export_all_button.setEnabled(bool(all_entries))
            self.archive_texture_edit_material_button.setEnabled(
                isinstance(single_selected_entry, ArchiveEntry) and is_material_sidecar_entry(single_selected_entry)
            )

        def _open_selected_archive_texture_reference(self) -> None:
            selected_references = self._selected_archive_texture_references()
            reference = selected_references[0] if len(selected_references) == 1 else self._current_archive_texture_reference()
            resolved_entry = getattr(reference, "resolved_entry", None) if reference is not None else None
            if not isinstance(resolved_entry, ArchiveEntry):
                self.set_status_message("Select a resolved referenced file first.", error=True)
                return
            semantic_sidecar_texts = tuple(
                str(text or "") for text in getattr(reference, "sidecar_texts", ()) if str(text or "").strip()
            ) if reference is not None else ()

            def _task(log: Callable[[str], None]) -> ArchivePreviewResult:
                log(f"Preparing referenced-file preview for {resolved_entry.path}...")
                texconv_text = self.texconv_path_edit.text().strip()
                texconv_path = Path(texconv_text).expanduser() if texconv_text else None
                preview_settings = self._current_model_preview_render_settings()
                return build_archive_preview_result(
                    texconv_path,
                    resolved_entry,
                    texture_entries_by_normalized_path=self.archive_entries_by_normalized_path,
                    texture_entries_by_basename=self.archive_entries_by_basename,
                    sidecar_entries_by_texture_path=self.archive_sidecar_entries_by_texture_path,
                    sidecar_entries_by_texture_basename=self.archive_sidecar_entries_by_texture_basename,
                    semantic_sidecar_texts=semantic_sidecar_texts,
                    visible_texture_mode=preview_settings.visible_texture_mode,
                )

            def _handle_complete(result: object) -> None:
                if not isinstance(result, ArchivePreviewResult):
                    self.set_status_message("Referenced-file preview finished with an unexpected result payload.", error=True)
                    return
                self._show_archive_reference_preview_dialog(resolved_entry, result)
                self.set_status_message(f"Opened preview for {resolved_entry.basename}.")

            self._run_utility_task(
                status_message=f"Preparing preview for {resolved_entry.basename}...",
                task=_task,
                on_complete=_handle_complete,
                show_archive_progress=True,
            )

        def _export_selected_archive_texture_reference(self) -> None:
            selected_entries = self._resolved_archive_reference_entries(self._selected_archive_texture_references())
            if not selected_entries:
                self.set_status_message("Select one or more resolved referenced files first.", error=True)
                return
            self._export_archive_reference_entries_to_folder(
                selected_entries,
                title="Export Selected Referenced Files",
            )

        def _export_all_archive_texture_references(self) -> None:
            resolved_entries = self._resolved_archive_reference_entries(self.current_archive_model_texture_references)
            if not resolved_entries:
                self.set_status_message("No resolved referenced files are available to export.", error=True)
                return
            self._export_archive_reference_entries_to_folder(
                resolved_entries,
                title="Export All Referenced Files",
            )

        def _choose_archive_write_target(
            self,
            *,
            title: str,
            message: str,
            allow_archive_patch: bool,
        ) -> str:
            dialog = QMessageBox(self)
            dialog.setIcon(QMessageBox.Question)
            dialog.setWindowTitle(title)
            dialog.setText(message)
            dialog.setInformativeText(
                "Patch Game Archives updates the installed package files and recalculates checksums. "
                "Write Mod-Ready Loose File creates a loose mod package instead."
            )
            patch_button = None
            if allow_archive_patch:
                patch_button = dialog.addButton("Patch Game Archives", QMessageBox.AcceptRole)
            loose_button = dialog.addButton("Write Mod-Ready Loose File", QMessageBox.ActionRole)
            cancel_button = dialog.addButton(QMessageBox.Cancel)
            dialog.exec()
            clicked = dialog.clickedButton()
            if patch_button is not None and clicked is patch_button:
                return "patch"
            if clicked is loose_button:
                return "loose"
            if clicked is cancel_button:
                return ""
            return ""

        def _prompt_archive_mod_ready_export_target(
            self,
            *,
            browse_title: str,
            initial_export_root: Path,
            initial_package_info: ModPackageInfo,
            initial_create_no_encrypt: bool,
            initial_include_related_files: bool = False,
            show_include_related_files_option: bool = False,
            dialog_title: str = "Write Mod-Ready Loose File",
        ) -> Optional[Tuple[Path, ModPackageInfo, bool, bool, ModPackageExportOptions]]:
            dialog = QDialog(self)
            dialog.setWindowTitle(dialog_title)
            dialog.setModal(True)
            dialog.resize(860, 460 if show_include_related_files_option else 420)

            layout = QVBoxLayout(dialog)
            layout.setContentsMargins(12, 12, 12, 12)
            layout.setSpacing(10)

            intro_label = QLabel(
                "Choose one shared mod-package export profile. The same metadata and structure rules are used by every mod-ready export path."
                + (
                    " You can also include the resolved related DDS and sidecar files that were detected for the selected mesh."
                    if show_include_related_files_option
                    else ""
                )
            )
            intro_label.setWordWrap(True)
            intro_label.setObjectName("HintLabel")
            layout.addWidget(intro_label)

            form_layout = QGridLayout()
            form_layout.setHorizontalSpacing(8)
            form_layout.setVerticalSpacing(8)

            export_root_edit = QLineEdit(str(initial_export_root))
            browse_button = QPushButton("Browse...")
            title_edit = QLineEdit(str(getattr(initial_package_info, "title", "") or "").strip())
            version_edit = QLineEdit(str(getattr(initial_package_info, "version", "") or "").strip())
            author_edit = QLineEdit(str(getattr(initial_package_info, "author", "") or "").strip())
            description_edit = QLineEdit(str(getattr(initial_package_info, "description", "") or "").strip())
            no_encrypt_checkbox = QCheckBox(MOD_PACKAGE_METADATA_ARTIFACTS_BY_KEY["no_encrypt"].label)
            no_encrypt_checkbox.setChecked(bool(initial_create_no_encrypt))
            manager_combo = QComboBox()
            manager_combo.addItem("Universal metadata (best effort)", "universal")
            manager_combo.addItem("JSON Mod Manager", "json_mod_manager")
            manager_combo.addItem("CDUMM", "cdumm")
            manager_combo.addItem("Definitive Mod Manager", "dmm")
            manager_combo.addItem("Crimson Sharp / Crimson Browser", "crimson_sharp")
            structure_combo = QComboBox()
            structure_combo.addItem("Game-relative folders", "game_relative")
            structure_combo.addItem("files/ wrapper", "files_wrapper")
            create_zip_checkbox = QCheckBox(MOD_PACKAGE_METADATA_ARTIFACTS_BY_KEY["ready_zip"].label)
            create_zip_checkbox.setChecked(False)
            mod_json_checkbox = QCheckBox(MOD_PACKAGE_METADATA_ARTIFACTS_BY_KEY["mod_json"].label)
            mod_json_checkbox.setChecked(True)
            modinfo_json_checkbox = QCheckBox(MOD_PACKAGE_METADATA_ARTIFACTS_BY_KEY["modinfo_json"].label)
            modinfo_json_checkbox.setChecked(True)
            manifest_json_checkbox = QCheckBox(MOD_PACKAGE_METADATA_ARTIFACTS_BY_KEY["manifest_json"].label)
            manifest_json_checkbox.setChecked(True)
            info_json_checkbox = QCheckBox(MOD_PACKAGE_METADATA_ARTIFACTS_BY_KEY["info_json"].label)
            info_json_checkbox.setChecked(True)
            conflict_mode_combo = QComboBox()
            conflict_mode_combo.addItem("Normal conflicts", "")
            conflict_mode_combo.addItem("Override wins", "override")
            target_language_edit = QLineEdit()
            target_language_edit.setPlaceholderText("Optional, e.g. ko")
            include_related_files_checkbox = QCheckBox("Include resolved related files (textures, .xml, .pami)")
            include_related_files_checkbox.setChecked(bool(initial_include_related_files))
            include_related_files_checkbox.setVisible(bool(show_include_related_files_option))

            title_edit.setPlaceholderText(MOD_READY_PACKAGE_TITLE)
            version_edit.setPlaceholderText(MOD_READY_PACKAGE_VERSION)
            author_edit.setPlaceholderText(MOD_READY_PACKAGE_AUTHOR)
            description_edit.setPlaceholderText(MOD_READY_PACKAGE_DESCRIPTION)

            form_layout.addWidget(QLabel("Parent export root"), 0, 0)
            form_layout.addWidget(export_root_edit, 0, 1)
            form_layout.addWidget(browse_button, 0, 2)
            form_layout.addWidget(QLabel("Package title"), 1, 0)
            form_layout.addWidget(title_edit, 1, 1, 1, 2)
            form_layout.addWidget(QLabel("Version"), 2, 0)
            form_layout.addWidget(version_edit, 2, 1, 1, 2)
            form_layout.addWidget(QLabel("Author"), 3, 0)
            form_layout.addWidget(author_edit, 3, 1, 1, 2)
            form_layout.addWidget(QLabel("Description"), 4, 0)
            form_layout.addWidget(description_edit, 4, 1, 1, 2)
            form_layout.addWidget(QLabel("Manager profile"), 5, 0)
            form_layout.addWidget(manager_combo, 5, 1, 1, 2)
            form_layout.addWidget(make_help_button("Choose the metadata/layout profile to target. Universal writes broadly compatible metadata; individual profiles bias the folder structure for that manager."), 5, 3)
            form_layout.addWidget(QLabel("Folder structure"), 6, 0)
            form_layout.addWidget(structure_combo, 6, 1, 1, 2)
            form_layout.addWidget(make_help_button("Game-relative folders write files directly under paths such as object/... . The files/ wrapper places payload files under files/ and points metadata at that folder."), 6, 3)
            conflict_mode_label = QLabel("Conflict mode")
            target_language_label = QLabel("Target language")
            conflict_mode_help = make_help_button("CDUMM compatibility metadata. Normal leaves manager conflict behavior unchanged; Override asks compatible managers to prefer this mod when conflicts are detected.")
            target_language_help = make_help_button("Optional CDUMM compatibility metadata for language-specific packages. Leave empty for general packages.")
            form_layout.addWidget(conflict_mode_label, 7, 0)
            form_layout.addWidget(conflict_mode_combo, 7, 1, 1, 2)
            form_layout.addWidget(conflict_mode_help, 7, 3)
            form_layout.addWidget(target_language_label, 8, 0)
            form_layout.addWidget(target_language_edit, 8, 1, 1, 2)
            form_layout.addWidget(target_language_help, 8, 3)
            metadata_checks = QGridLayout()
            metadata_checks.setContentsMargins(0, 0, 0, 0)
            metadata_checks.setHorizontalSpacing(18)
            metadata_checks.setVerticalSpacing(6)
            metadata_options = (
                ("manifest_json", manifest_json_checkbox),
                ("mod_json", mod_json_checkbox),
                ("modinfo_json", modinfo_json_checkbox),
                ("info_json", info_json_checkbox),
                ("no_encrypt", no_encrypt_checkbox),
                ("ready_zip", create_zip_checkbox),
            )
            for index, (key, checkbox) in enumerate(metadata_options):
                checkbox.setToolTip(
                    f"<qt><div style='width: 360px; white-space: normal;'>{escape(MOD_PACKAGE_METADATA_ARTIFACTS_BY_KEY[key].description)}</div></qt>"
                )
                option_row = QHBoxLayout()
                option_row.setContentsMargins(0, 0, 0, 0)
                option_row.setSpacing(6)
                option_row.addWidget(checkbox)
                option_row.addWidget(make_help_button(MOD_PACKAGE_METADATA_ARTIFACTS_BY_KEY[key].description))
                option_row.addStretch(1)
                metadata_checks.addLayout(option_row, index // 2, index % 2)
            metadata_checks.setColumnStretch(0, 1)
            metadata_checks.setColumnStretch(1, 1)
            form_layout.addWidget(QLabel("Generate"), 9, 0)
            form_layout.addLayout(metadata_checks, 9, 1, 1, 3)
            form_layout.addWidget(include_related_files_checkbox, 10, 0, 1, 3)
            form_layout.setColumnStretch(1, 1)
            layout.addLayout(form_layout)

            def _apply_manager_profile() -> None:
                profile_options = mod_package_export_options_for_manager(str(manager_combo.currentData() or "universal"))
                structure_index = structure_combo.findData(profile_options.structure)
                if structure_index >= 0:
                    structure_combo.setCurrentIndex(structure_index)
                uses_manager_metadata = mod_package_profile_uses_manager_metadata(str(manager_combo.currentData() or "universal"))
                for widget in (
                    conflict_mode_label,
                    conflict_mode_combo,
                    conflict_mode_help,
                    target_language_label,
                    target_language_edit,
                    target_language_help,
                ):
                    widget.setVisible(uses_manager_metadata)

            manager_combo.currentIndexChanged.connect(_apply_manager_profile)
            _apply_manager_profile()

            hint_label = QLabel(
                "Warning: rebuilding a mesh payload does not automatically rewrite every referenced DDS or the companion material sidecars. "
                "For many PAC meshes, the matching .pac.xml still controls important material and texture assignments. "
                "For PAM / PAMLOD meshes, the matching .pami often carries the same kind of texture-role data. "
                "If the imported mesh changes submesh/material usage, you may also need to review the linked DDS files and those companion sidecars."
            )
            hint_label.setWordWrap(True)
            hint_label.setObjectName("HintLabel")
            layout.addWidget(hint_label)

            button_row = QHBoxLayout()
            button_row.setSpacing(8)
            button_row.addStretch(1)
            cancel_button = QPushButton("Cancel")
            continue_button = QPushButton("Continue")
            continue_button.setDefault(True)
            button_row.addWidget(cancel_button)
            button_row.addWidget(continue_button)
            layout.addLayout(button_row)

            result: List[object] = []

            def _browse_export_root() -> None:
                selected_dir = QFileDialog.getExistingDirectory(
                    dialog,
                    browse_title,
                    export_root_edit.text().strip() or str(initial_export_root),
                )
                if selected_dir:
                    export_root_edit.setText(selected_dir)

            def _accept() -> None:
                export_root_text = export_root_edit.text().strip()
                if not export_root_text:
                    QMessageBox.warning(dialog, dialog_title, "Parent export root is required.")
                    return
                export_root = Path(export_root_text).expanduser()
                package_info = ModPackageInfo(
                    title=title_edit.text().strip() or MOD_READY_PACKAGE_TITLE,
                    version=version_edit.text().strip() or MOD_READY_PACKAGE_VERSION,
                    author=author_edit.text().strip(),
                    description=description_edit.text().strip(),
                    nexus_url="",
                )
                selected_profile = str(manager_combo.currentData() or "universal")
                base_options = mod_package_export_options_for_manager(selected_profile)
                uses_manager_metadata = mod_package_profile_uses_manager_metadata(selected_profile)
                manager_targets = (
                    ("json_mod_manager", "cdumm", "dmm", "crimson_sharp")
                    if selected_profile == "universal"
                    else tuple(base_options.manager_targets)
                )
                export_options = ModPackageExportOptions(
                    manager_targets=manager_targets,
                    structure=str(structure_combo.currentData() or base_options.structure),
                    create_manifest_json=manifest_json_checkbox.isChecked(),
                    create_mod_json=mod_json_checkbox.isChecked(),
                    create_modinfo_json=modinfo_json_checkbox.isChecked(),
                    create_info_json=info_json_checkbox.isChecked(),
                    create_no_encrypt_file=no_encrypt_checkbox.isChecked(),
                    create_zip=create_zip_checkbox.isChecked(),
                    conflict_mode=str(conflict_mode_combo.currentData() or "") if uses_manager_metadata else "",
                    target_language=target_language_edit.text().strip() if uses_manager_metadata else "",
                )
                result[:] = [
                    export_root,
                    package_info,
                    bool(no_encrypt_checkbox.isChecked()),
                    bool(include_related_files_checkbox.isChecked()),
                    export_options,
                ]
                dialog.accept()

            browse_button.clicked.connect(_browse_export_root)
            cancel_button.clicked.connect(dialog.reject)
            continue_button.clicked.connect(_accept)

            if dialog.exec() != QDialog.Accepted or len(result) != 5:
                return None

            export_root = Path(result[0]).expanduser()
            package_info = result[1] if isinstance(result[1], ModPackageInfo) else initial_package_info
            create_no_encrypt_file = bool(result[2])
            include_related_files = bool(result[3])
            export_options = result[4] if isinstance(result[4], ModPackageExportOptions) else ModPackageExportOptions()

            self.mod_ready_export_root_edit.setText(str(export_root))
            self.mod_ready_package_title_edit.setText(package_info.title)
            self.mod_ready_package_version_edit.setText(package_info.version)
            self.mod_ready_package_author_edit.setText(package_info.author)
            self.mod_ready_package_description_edit.setText(package_info.description)
            self.mod_ready_create_no_encrypt_checkbox.setChecked(create_no_encrypt_file)
            self.schedule_settings_save()

            return export_root, package_info, create_no_encrypt_file, include_related_files, export_options

        def _collect_archive_mod_ready_export_target(
            self,
            *,
            browse_title: str,
            prompt_for_metadata: bool = False,
            initial_include_related_files: bool = False,
            show_include_related_files_option: bool = False,
            dialog_title: str = "Write Mod-Ready Loose File",
        ) -> Optional[Tuple[Path, ModPackageInfo, bool, bool, ModPackageExportOptions]]:
            config = self.collect_config()
            export_root_text = str(getattr(config, "mod_ready_export_root", "") or "").strip()
            if export_root_text:
                export_root = Path(export_root_text).expanduser()
            else:
                output_root_text = str(getattr(config, "output_root", "") or "").strip()
                default_root = (
                    resolve_default_mod_ready_export_root(Path(output_root_text).expanduser())
                    if output_root_text
                    else (self.settings_file_path.parent / MOD_READY_EXPORT_DIRNAME)
                )
                selected_dir = QFileDialog.getExistingDirectory(self, browse_title, str(default_root))
                if not selected_dir:
                    return None
                export_root = Path(selected_dir)
            package_info = ModPackageInfo(
                title=str(getattr(config, "mod_ready_package_title", MOD_READY_PACKAGE_TITLE) or "").strip() or MOD_READY_PACKAGE_TITLE,
                version=str(getattr(config, "mod_ready_package_version", MOD_READY_PACKAGE_VERSION) or "").strip() or MOD_READY_PACKAGE_VERSION,
                author=str(getattr(config, "mod_ready_package_author", MOD_READY_PACKAGE_AUTHOR) or "").strip(),
                description=str(getattr(config, "mod_ready_package_description", MOD_READY_PACKAGE_DESCRIPTION) or "").strip(),
                nexus_url=str(getattr(config, "mod_ready_package_nexus_url", MOD_READY_PACKAGE_NEXUS_URL) or "").strip(),
            )
            create_no_encrypt_file = bool(getattr(config, "mod_ready_create_no_encrypt_file", True))
            if prompt_for_metadata:
                return self._prompt_archive_mod_ready_export_target(
                    browse_title=browse_title,
                    initial_export_root=export_root,
                    initial_package_info=package_info,
                    initial_create_no_encrypt=create_no_encrypt_file,
                    initial_include_related_files=initial_include_related_files,
                    show_include_related_files_option=show_include_related_files_option,
                    dialog_title=dialog_title,
                )
            return (
                export_root,
                package_info,
                create_no_encrypt_file,
                False,
                ModPackageExportOptions(create_no_encrypt_file=create_no_encrypt_file),
            )

        def _archive_tree_column_labels(self) -> List[str]:
            header_item = self.archive_tree.headerItem()
            return [
                header_item.text(column) or f"Column {column + 1}"
                for column in range(self.archive_tree.columnCount())
            ]

        def _archive_tree_visible_column_count(self) -> int:
            return sum(
                1
                for column in range(self.archive_tree.columnCount())
                if not self.archive_tree.isColumnHidden(column)
            )

        def _parse_archive_tree_column_ints(self, key: str, *, clamp_to_columns: bool = True) -> List[int]:
            raw_value = self.settings.value(key)
            if raw_value in (None, ""):
                return []
            if isinstance(raw_value, str):
                parts = [part.strip() for part in raw_value.split(",") if part.strip()]
            elif isinstance(raw_value, (list, tuple)):
                parts = list(raw_value)
            else:
                return []
            values: List[int] = []
            for part in parts:
                try:
                    value = int(part)
                except (TypeError, ValueError):
                    continue
                if not clamp_to_columns or 0 <= value < self.archive_tree.columnCount():
                    values.append(value)
            return values

        def _apply_archive_tree_header_settings(self) -> None:
            if not hasattr(self, "archive_tree"):
                return
            header = self.archive_tree.header()
            if header is None:
                return
            widths = self._parse_archive_tree_column_ints("ui/archive_tree_column_widths", clamp_to_columns=False)
            for column, width in enumerate(widths[: self.archive_tree.columnCount()]):
                if width > 0:
                    header.resizeSection(column, max(48, width))
            order = self._parse_archive_tree_column_ints("ui/archive_tree_column_order")
            if len(order) == self.archive_tree.columnCount() and len(set(order)) == self.archive_tree.columnCount():
                for target_visual, logical_index in enumerate(order):
                    current_visual = header.visualIndex(logical_index)
                    if current_visual >= 0 and current_visual != target_visual:
                        header.moveSection(current_visual, target_visual)
            hidden_columns = set(self._parse_archive_tree_column_ints("ui/archive_tree_hidden_columns"))
            if len(hidden_columns) >= self.archive_tree.columnCount():
                hidden_columns = set()
            for column in range(self.archive_tree.columnCount()):
                self.archive_tree.setColumnHidden(column, column in hidden_columns)

        def _save_archive_tree_header_settings(self) -> None:
            if not hasattr(self, "archive_tree"):
                return
            header = self.archive_tree.header()
            if header is None:
                return
            order = [
                str(header.logicalIndex(visual_index))
                for visual_index in range(self.archive_tree.columnCount())
            ]
            widths = [
                str(max(1, header.sectionSize(column)))
                for column in range(self.archive_tree.columnCount())
            ]
            hidden = [
                str(column)
                for column in range(self.archive_tree.columnCount())
                if self.archive_tree.isColumnHidden(column)
            ]
            self.settings.setValue("ui/archive_tree_column_order", ",".join(order))
            self.settings.setValue("ui/archive_tree_column_widths", ",".join(widths))
            self.settings.setValue("ui/archive_tree_hidden_columns", ",".join(hidden))

        def _set_archive_tree_column_visible(self, column: int, visible: bool) -> None:
            if not (0 <= column < self.archive_tree.columnCount()):
                return
            if not visible and self._archive_tree_visible_column_count() <= 1:
                self.archive_tree.setColumnHidden(column, False)
                return
            self.archive_tree.setColumnHidden(column, not visible)
            self.schedule_settings_save()

        def _reset_archive_tree_columns(self) -> None:
            header = self.archive_tree.header()
            if header is None:
                return
            for column in range(self.archive_tree.columnCount()):
                self.archive_tree.setColumnHidden(column, False)
            for logical_index in range(self.archive_tree.columnCount()):
                current_visual = header.visualIndex(logical_index)
                if current_visual >= 0 and current_visual != logical_index:
                    header.moveSection(current_visual, logical_index)
            default_widths = [260, 220, 78, 145, 72, 130, 360]
            for column, width in enumerate(default_widths[: self.archive_tree.columnCount()]):
                header.resizeSection(column, width)
            self.schedule_settings_save()
            self._schedule_column_autofit()

        def _show_archive_tree_header_context_menu(self, position) -> None:
            if not hasattr(self, "archive_tree"):
                return
            menu = QMenu(self)
            for column, label in enumerate(self._archive_tree_column_labels()):
                action = menu.addAction(label)
                action.setCheckable(True)
                action.setChecked(not self.archive_tree.isColumnHidden(column))
                action.setEnabled(
                    self.archive_tree.isColumnHidden(column)
                    or self._archive_tree_visible_column_count() > 1
                )
                action.toggled.connect(
                    lambda checked, current_column=column: self._set_archive_tree_column_visible(current_column, checked)
                )
            menu.addSeparator()
            show_all_action = menu.addAction("Show All Columns")
            show_all_action.triggered.connect(lambda _checked=False: self._set_all_archive_tree_columns_visible())
            reset_action = menu.addAction("Reset Columns")
            reset_action.triggered.connect(lambda _checked=False: self._reset_archive_tree_columns())
            menu.exec(self.archive_tree.header().mapToGlobal(position))

        def _set_all_archive_tree_columns_visible(self) -> None:
            for column in range(self.archive_tree.columnCount()):
                self.archive_tree.setColumnHidden(column, False)
            self.schedule_settings_save()

        def _archive_entry_at_tree_position(self, position) -> Optional[ArchiveEntry]:
            item = self.archive_tree.itemAt(position)
            if item is None:
                return None
            kind = self._archive_tree_item_kind(item)
            value = self._archive_tree_item_value(item)
            if kind != "file" or not isinstance(value, int):
                return None
            if 0 <= value < len(self.archive_filtered_entries):
                return self.archive_filtered_entries[value]
            return None

        def _find_archive_entry_by_virtual_path(self, virtual_path: str) -> Optional[ArchiveEntry]:
            normalized = virtual_path.replace("\\", "/").strip().lower()
            matches = self.archive_entries_by_normalized_path.get(normalized, [])
            return matches[0] if matches else None

        def _show_archive_tree_context_menu(self, position) -> None:
            entry = self._archive_entry_at_tree_position(position)
            if entry is None:
                return

            menu = QMenu(self)
            if entry.extension in ARCHIVE_MESH_EXTENSIONS:
                export_obj_action = menu.addAction("Export OBJ...")
                export_obj_action.triggered.connect(lambda _checked=False, current_entry=entry: self._start_archive_mesh_export(current_entry, "obj"))
                export_fbx_action = menu.addAction("Export FBX...")
                export_fbx_action.triggered.connect(lambda _checked=False, current_entry=entry: self._start_archive_mesh_export(current_entry, "fbx"))
                menu.addSeparator()
                import_preview_action = menu.addAction("Import Mesh Preview...")
                import_preview_action.triggered.connect(
                    lambda _checked=False, current_entry=entry: self._start_archive_mesh_import_preview(current_entry)
                )
                import_patch_action = menu.addAction("Import Mesh...")
                import_patch_action.triggered.connect(
                    lambda _checked=False, current_entry=entry: self._start_archive_mesh_patch(current_entry)
                )

            if entry.extension in ARCHIVE_AUDIO_EXPORT_EXTENSIONS or entry.extension in ARCHIVE_AUDIO_PATCH_EXTENSIONS:
                if not menu.isEmpty():
                    menu.addSeparator()
                export_audio_action = menu.addAction("Export WAV...")
                export_audio_action.triggered.connect(
                    lambda _checked=False, current_entry=entry: self._start_archive_audio_export(current_entry)
                )
                if entry.extension in ARCHIVE_AUDIO_PATCH_EXTENSIONS:
                    import_audio_action = menu.addAction("Import WAV + Patch to Game...")
                    import_audio_action.triggered.connect(
                        lambda _checked=False, current_entry=entry: self._start_archive_audio_patch(current_entry)
                    )

            if menu.isEmpty():
                return
            menu.exec(self.archive_tree.viewport().mapToGlobal(position))

        def _apply_archive_patch_result(self, patch_result: ArchivePatchResult) -> None:
            for normalized_path, updated_entry in patch_result.changed_entries.items():
                for existing_entry in self.archive_entries_by_normalized_path.get(normalized_path, []):
                    if existing_entry.pamt_path.resolve() != updated_entry.pamt_path.resolve():
                        continue
                    existing_entry.paz_file = updated_entry.paz_file
                    existing_entry.offset = updated_entry.offset
                    existing_entry.comp_size = updated_entry.comp_size
                    existing_entry.orig_size = updated_entry.orig_size
                    existing_entry.flags = updated_entry.flags
                    existing_entry.paz_index = updated_entry.paz_index
            self.archive_preview_cache.clear()
            changed_paths = tuple(str(path or "").replace("\\", "/").strip().lower() for path in patch_result.changed_entries)
            if any(
                _is_material_sidecar_extension(
                    PurePosixPath(path).suffix,
                    PurePosixPath(path).name,
                )
                or path.endswith(".dds")
                for path in changed_paths
            ):
                self.archive_sidecar_generation += 1
                self.archive_sidecar_entries_by_texture_path = {}
                self.archive_sidecar_entries_by_texture_basename = {}
                if self.archive_entries and self._current_archive_performance_settings().enable_sidecar_indexing:
                    self.archive_sidecar_pending_start = True
                    QTimer.singleShot(0, self._start_archive_sidecar_index_worker)
                else:
                    self.archive_sidecar_pending_start = False

        def _show_archive_import_preview(
            self,
            entry: ArchiveEntry,
            import_result: MeshImportPreviewResult,
            *,
            patched: bool,
            backup_dir: Optional[Path] = None,
            loose_package_root: Optional[Path] = None,
        ) -> None:
            self._attach_archive_model_preview_images(import_result.preview_model)
            detail_lines = list(import_result.summary_lines)
            if import_result.import_issues:
                detail_lines.append("")
                detail_lines.append("Import validation:")
                for issue in import_result.import_issues:
                    detail_lines.append(f"- {issue.status}: {issue.title} - {issue.detail}")
                    for diff in tuple(getattr(issue, "diffs", ()) or ())[:3]:
                        diff_detail = str(getattr(diff, "detail", "") or "").strip()
                        if diff_detail:
                            detail_lines.append(f"  * {diff_detail}")
                    extra_diff_count = max(0, len(tuple(getattr(issue, "diffs", ()) or ())) - 3)
                    if extra_diff_count > 0:
                        detail_lines.append(f"  * ... {extra_diff_count:,} more difference(s)")
            if patched and backup_dir is not None:
                detail_lines.append(f"Backup: {backup_dir}")
            if not patched and loose_package_root is not None:
                detail_lines.append(f"Loose export: {loose_package_root}")
            warning_badge = ""
            warning_text = ""
            if not patched and loose_package_root is not None:
                warning_badge = "Loose export"
                warning_text = f"This rebuilt mesh has been written to the mod-ready package at {loose_package_root}."
            elif not patched:
                warning_badge = "Import preview"
                warning_text = "This rebuilt mesh preview has not been written back to the game archives yet."
            prepared_model, prepared_preview_model = ModelPreviewWidget.prepare_model_preview(import_result.preview_model)
            preview_result = ArchivePreviewResult(
                status="ok",
                title=entry.basename,
                metadata_summary=(
                    f"{entry.extension} | {import_result.parsed_mesh.total_vertices:,} vertices"
                    f" | {import_result.parsed_mesh.total_faces:,} faces"
                ),
                detail_text="\n".join(detail_lines),
                preview_model=prepared_model,
                prepared_preview_model=prepared_preview_model,
                model_texture_references=tuple(import_result.texture_references),
                preferred_view="model",
                warning_badge=warning_badge,
                warning_text=warning_text,
            )
            self.archive_preview_requested_loose = False
            self.current_archive_preview_result = preview_result
            self._show_archive_preview_result(preview_result, use_loose=False)

        def _confirm_archive_mesh_import_commit(
            self,
            entry: ArchiveEntry,
            import_result: MeshImportPreviewResult,
            *,
            destination: str,
            source_obj_path: Path,
        ) -> bool:
            issues = tuple(import_result.import_issues or ())
            actionable_issues = [
                issue for issue in issues if issue.status != ImportIssueStatus.AUTO_FIXED.value
            ]
            if not actionable_issues:
                return True

            status_counts = Counter(issue.status for issue in issues)
            message_lines = [
                f"{source_obj_path.name} for {entry.basename} has import validation findings.",
                "",
                "Summary:",
                ", ".join(
                    f"{status_counts.get(status, 0):,} {status}"
                    for status in (
                        ImportIssueStatus.AUTO_FIXED.value,
                        ImportIssueStatus.WARNING.value,
                        ImportIssueStatus.REQUIRES_MANUAL_REVIEW.value,
                    )
                    if status_counts.get(status, 0) > 0
                ),
                "",
                "Actionable findings:",
            ]
            for issue in actionable_issues[:6]:
                message_lines.append(f"- {issue.status}: {issue.title}")
                if issue.detail:
                    message_lines.append(f"  {issue.detail}")
            remaining_count = len(actionable_issues) - 6
            if remaining_count > 0:
                message_lines.append(f"... and {remaining_count:,} more issue(s) in the preview details.")
            message_lines.append("")
            message_lines.append(
                "Continue anyway?"
                if any(issue.status == ImportIssueStatus.REQUIRES_MANUAL_REVIEW.value for issue in actionable_issues)
                else "Continue with the import?"
            )

            prompt = QMessageBox(self)
            prompt.setIcon(QMessageBox.Warning)
            prompt.setWindowTitle(
                "Review Import Compatibility"
                if any(issue.status == ImportIssueStatus.REQUIRES_MANUAL_REVIEW.value for issue in actionable_issues)
                else "Review Import Warnings"
            )
            prompt.setText("\n".join(message_lines))
            prompt.setStandardButtons(QMessageBox.Yes | QMessageBox.No)
            prompt.setDefaultButton(QMessageBox.No)
            yes_button = prompt.button(QMessageBox.Yes)
            if yes_button is not None:
                yes_button.setText(
                    "Patch Anyway" if destination == "patch" else "Export Anyway"
                )
            no_button = prompt.button(QMessageBox.No)
            if no_button is not None:
                no_button.setText("Cancel")
            return prompt.exec() == QMessageBox.Yes

        def _attach_archive_model_preview_images(self, preview_model: Optional[object]) -> None:
            if preview_model is None:
                return
            meshes = getattr(preview_model, "meshes", None)
            if not meshes:
                return
            for mesh in meshes:
                texture_slots = (
                    ("preview_texture_path", "preview_texture_image"),
                    ("preview_normal_texture_path", "preview_normal_texture_image"),
                    ("preview_material_texture_path", "preview_material_texture_image"),
                    ("preview_height_texture_path", "preview_height_texture_image"),
                )
                for path_attr, image_attr in texture_slots:
                    preview_texture_path = str(getattr(mesh, path_attr, "") or "").strip()
                    if not preview_texture_path or getattr(mesh, image_attr, None) is not None:
                        continue
                    reader = QImageReader(preview_texture_path)
                    image = reader.read()
                    if image.isNull():
                        continue
                    setattr(mesh, image_attr, image)

        def _prompt_archive_mesh_related_file_selection(
            self,
            entry: ArchiveEntry,
            *,
            title: str,
            intro_text: str,
            confirm_button_text: str,
        ) -> Optional[Tuple[ArchiveEntry, ...]]:
            references = self._current_archive_related_references_for_entry(entry)
            return self._prompt_archive_reference_selection(
                title=title,
                intro_text=intro_text,
                references=references,
                confirm_button_text=confirm_button_text,
            )

        def _prompt_archive_mesh_import_supplemental_files(
            self,
            entry: ArchiveEntry,
            *,
            title: str,
        ) -> Optional[Tuple[Path, ...]]:
            decision = QMessageBox.question(
                self,
                title,
                (
                    f"Do you want to add local supplemental files for {entry.basename}?\n\n"
                    "Supported files:\n"
                    "  - .png / .jpg / .jpeg replacement texture sources for static scene imports\n"
                    "  - .dds texture overrides\n"
                    "  - .xml / .pac_xml PAC material sidecars\n"
                    "  - .pami PAM material sidecars\n\n"
                    "Selected files will be used for rebuilt preview, and mapped files can also be included in the loose export package."
                ),
                QMessageBox.Yes | QMessageBox.No | QMessageBox.Cancel,
                QMessageBox.No,
            )
            if decision == QMessageBox.Cancel:
                return None
            if decision != QMessageBox.Yes:
                return ()

            source_dialog = QMessageBox(self)
            source_dialog.setWindowTitle(title)
            source_dialog.setIcon(QMessageBox.Question)
            source_dialog.setText("Select supplemental files or a folder?")
            source_dialog.setInformativeText(
                "Use a folder when replacement textures are already grouped together, such as a Blender export texture folder."
            )
            files_button = source_dialog.addButton("Select Files", QMessageBox.AcceptRole)
            folder_button = source_dialog.addButton("Select Folder", QMessageBox.ActionRole)
            source_dialog.addButton(QMessageBox.Cancel)
            source_dialog.setDefaultButton(files_button)
            source_dialog.exec()
            clicked_source = source_dialog.clickedButton()
            supported_suffixes = set(SCENE_TEXTURE_SOURCE_EXTENSIONS) | {".xml", ".pami", ".pac_xml", ".pam_xml", ".pamlod_xml"}
            if clicked_source == folder_button:
                selected_dir = QFileDialog.getExistingDirectory(
                    self,
                    title,
                    str(self.settings_file_path.parent),
                )
                if not selected_dir:
                    return ()
                return tuple(
                    path
                    for path in sorted(Path(selected_dir).rglob("*"))
                    if path.is_file() and path.suffix.lower() in supported_suffixes
                )
            if clicked_source != files_button:
                return None

            selected_files, _selected_filter = QFileDialog.getOpenFileNames(
                self,
                title,
                str(self.settings_file_path.parent),
                "Supplemental Files (*.png *.jpg *.jpeg *.dds *.xml *.pami *.pac_xml *.pam_xml *.pamlod_xml);;Texture Sources (*.png *.jpg *.jpeg *.dds);;DDS Files (*.dds);;Image Files (*.png *.jpg *.jpeg);;Material Sidecars (*.xml *.pami *.pac_xml *.pam_xml *.pamlod_xml)",
            )
            if not selected_files:
                return ()
            return tuple(Path(path) for path in selected_files if path)

        @staticmethod
        def _archive_mesh_import_file_filter() -> str:
            return (
                "Mesh Files (*.obj *.dae *.gltf *.glb);;"
                "Wavefront OBJ (*.obj);;"
                "Collada DAE (*.dae);;"
                "glTF / GLB (*.gltf *.glb)"
            )

        @staticmethod
        def _has_valid_obj_roundtrip_sidecar(scene_path: Path) -> bool:
            candidate = Path(f"{scene_path}.meta.json")
            if not candidate.is_file():
                return False
            try:
                payload = json.loads(candidate.read_text(encoding="utf-8"))
            except Exception:
                return False
            if not isinstance(payload, dict):
                return False
            payload_format = str(payload.get("format", "") or "").strip()
            return not payload_format or payload_format in {"obj_meta_v1", "mesh_roundtrip_manifest_v2"}

        def _prompt_archive_mesh_import_setup(
            self,
            entry: ArchiveEntry,
            scene_path: Path,
            *,
            title: str,
        ) -> Optional[MeshImportSetupSelection]:
            try:
                scene_import_result = import_scene_mesh_with_report(scene_path)
            except Exception as exc:
                QMessageBox.warning(
                    self,
                    "Mesh Import Unsupported",
                    f"{scene_path.name} could not be imported.\n\n{exc}",
                )
                return None

            suffix = scene_path.suffix.lower()
            is_obj = suffix == ".obj"
            has_roundtrip_sidecar = self._has_valid_obj_roundtrip_sidecar(scene_path) if is_obj else False
            profile: Optional[ReplacementAssetProfile] = None
            try:
                original_data, _decompressed, _note = read_archive_entry_data(entry)
                profile = analyze_replacement_asset(
                    entry,
                    archive_entries_by_basename=dict(self.archive_entries_by_basename),
                    parsed_mesh=parse_mesh(original_data, entry.path),
                )
            except Exception:
                profile = None

            dialog = QDialog(self)
            dialog.setWindowTitle(title)
            dialog.setMinimumWidth(760)
            layout = QVBoxLayout(dialog)
            intro = QLabel(
                "Choose the import path and any supplemental files before opening Mesh Replacement Alignment."
            )
            intro.setWordWrap(True)
            intro.setObjectName("HintLabel")
            layout.addWidget(intro)

            source_group = QGroupBox("Source")
            source_layout = QGridLayout(source_group)
            source_layout.addWidget(QLabel("File"), 0, 0)
            source_label = QLabel(str(scene_path))
            source_label.setTextInteractionFlags(Qt.TextSelectableByMouse)
            source_label.setWordWrap(True)
            source_layout.addWidget(source_label, 0, 1)
            source_layout.addWidget(QLabel("Detected"), 1, 0)
            detected_label = QLabel(
                f"{scene_import_result.mesh.format.upper()} | "
                f"{len(scene_import_result.mesh.submeshes):,} submesh(es), "
                f"{scene_import_result.mesh.total_vertices:,} vertices, "
                f"{scene_import_result.mesh.total_faces:,} faces"
            )
            detected_label.setTextInteractionFlags(Qt.TextSelectableByMouse)
            source_layout.addWidget(detected_label, 1, 1)
            layout.addWidget(source_group)

            mode_group = QGroupBox("Import Mode")
            mode_layout = QVBoxLayout(mode_group)
            roundtrip_radio = QRadioButton("Round-trip edit")
            roundtrip_radio.setToolTip(
                "OBJ-only path for meshes exported by this app. Keeps original mesh structure and uses OBJ sidecar metadata when available."
            )
            static_radio = QRadioButton("Mesh Replacement")
            static_radio.setToolTip(
                "Maps an arbitrary static OBJ/DAE/GLB/glTF scene onto the selected original game mesh and opens Mesh Replacement Alignment."
            )
            mode_layout.addWidget(roundtrip_radio)
            mode_layout.addWidget(static_radio)
            availability = mesh_import_mode_availability(
                scene_path,
                has_roundtrip_sidecar=has_roundtrip_sidecar,
                static_supported=bool(profile is None or profile.export_supported),
            )
            if not availability.roundtrip_enabled:
                roundtrip_radio.setEnabled(False)
                roundtrip_radio.setToolTip("Round-trip edit is OBJ-only. DAE, GLB, and glTF use Mesh Replacement.")
            if not availability.static_enabled:
                static_radio.setEnabled(False)
                static_radio.setToolTip("\n".join(profile.errors) or "Mesh replacement is not enabled for this target asset.")
            guidance_label = QLabel(availability.guidance)
            guidance_label.setWordWrap(True)
            guidance_label.setObjectName("HintLabel")
            mode_layout.addWidget(guidance_label)
            if availability.default_mode == "roundtrip":
                roundtrip_radio.setChecked(True)
            elif availability.default_mode == "static_replacement":
                static_radio.setChecked(True)
            layout.addWidget(mode_group)

            diagnostics = list(scene_import_result.diagnostics)
            if profile is not None:
                diagnostics.append(f"Target compatibility: {profile.support_level} ({profile.category_hint}).")
                diagnostics.extend(profile.errors[:3])
                diagnostics.extend(profile.warnings[:3])
            if diagnostics:
                diagnostics_group = QGroupBox("Guidance")
                diagnostics_layout = QVBoxLayout(diagnostics_group)
                for line in diagnostics[:10]:
                    line_label = QLabel(str(line))
                    line_label.setWordWrap(True)
                    line_label.setObjectName("HintLabel")
                    diagnostics_layout.addWidget(line_label)
                layout.addWidget(diagnostics_group)

            supplemental_group = QGroupBox("Supplemental Files")
            supplemental_layout = QVBoxLayout(supplemental_group)
            supplemental_hint = QLabel(
                "Detected texture files are checked by default. Add local textures or material sidecars here instead of answering separate prompts."
            )
            supplemental_hint.setWordWrap(True)
            supplemental_hint.setObjectName("HintLabel")
            supplemental_layout.addWidget(supplemental_hint)
            supplemental_list = QListWidget()
            supplemental_list.setMinimumHeight(150)
            supplemental_list.setSelectionMode(QAbstractItemView.ExtendedSelection)
            supported_suffixes = set(SCENE_TEXTURE_SOURCE_EXTENSIONS) | {".xml", ".pami", ".pac_xml", ".pam_xml", ".pamlod_xml"}
            seen_paths: set[str] = set()

            def _add_supplemental_path(path: Path, *, checked: bool = True) -> None:
                try:
                    resolved = path.expanduser().resolve()
                except Exception:
                    return
                if not resolved.is_file() or resolved.suffix.lower() not in supported_suffixes:
                    return
                key = str(resolved).lower()
                if key in seen_paths:
                    return
                seen_paths.add(key)
                item = QListWidgetItem(resolved.name)
                item.setToolTip(str(resolved))
                item.setData(Qt.UserRole, str(resolved))
                item.setFlags(item.flags() | Qt.ItemIsUserCheckable)
                item.setCheckState(Qt.Checked if checked else Qt.Unchecked)
                supplemental_list.addItem(item)

            auto_paths = (
                tuple(scene_import_result.discovered_texture_files)
                + tuple(scene_import_result.extracted_embedded_files)
                + tuple(discover_scene_texture_files(scene_path, scene_import_result.mesh))
            )
            for auto_path in auto_paths:
                _add_supplemental_path(auto_path, checked=True)

            supplemental_layout.addWidget(supplemental_list)
            supplemental_buttons = QHBoxLayout()
            add_files_button = QPushButton("Add Files")
            add_folder_button = QPushButton("Add Folder")
            clear_button = QPushButton("Clear")
            supplemental_buttons.addWidget(add_files_button)
            supplemental_buttons.addWidget(add_folder_button)
            supplemental_buttons.addStretch(1)
            supplemental_buttons.addWidget(clear_button)
            supplemental_layout.addLayout(supplemental_buttons)
            layout.addWidget(supplemental_group)

            def _add_files() -> None:
                selected_files, _selected_filter = QFileDialog.getOpenFileNames(
                    dialog,
                    "Add Supplemental Files",
                    str(scene_path.parent),
                    "Supplemental Files (*.png *.jpg *.jpeg *.dds *.xml *.pami *.pac_xml *.pam_xml *.pamlod_xml);;Texture Sources (*.png *.jpg *.jpeg *.dds);;DDS Files (*.dds);;Material Sidecars (*.xml *.pami *.pac_xml *.pam_xml *.pamlod_xml)",
                )
                for raw_path in selected_files:
                    if raw_path:
                        _add_supplemental_path(Path(raw_path), checked=True)

            def _add_folder() -> None:
                selected_dir = QFileDialog.getExistingDirectory(dialog, "Add Supplemental Folder", str(scene_path.parent))
                if not selected_dir:
                    return
                for candidate in sorted(Path(selected_dir).rglob("*")):
                    _add_supplemental_path(candidate, checked=True)

            def _clear_supplemental() -> None:
                supplemental_list.clear()
                seen_paths.clear()

            add_files_button.clicked.connect(_add_files)
            add_folder_button.clicked.connect(_add_folder)
            clear_button.clicked.connect(_clear_supplemental)

            button_row = QHBoxLayout()
            button_row.addStretch(1)
            cancel_button = QPushButton("Cancel")
            continue_button = QPushButton("Continue")
            continue_button.setDefault(True)
            button_row.addWidget(cancel_button)
            button_row.addWidget(continue_button)
            layout.addLayout(button_row)

            def _refresh_continue_state() -> None:
                continue_button.setEnabled(
                    (roundtrip_radio.isEnabled() and roundtrip_radio.isChecked())
                    or (static_radio.isEnabled() and static_radio.isChecked())
                )

            roundtrip_radio.toggled.connect(_refresh_continue_state)
            static_radio.toggled.connect(_refresh_continue_state)
            cancel_button.clicked.connect(dialog.reject)
            continue_button.clicked.connect(dialog.accept)
            _refresh_continue_state()

            if dialog.exec() != QDialog.Accepted:
                return None
            import_mode = "roundtrip" if roundtrip_radio.isChecked() else "static_replacement"
            if import_mode == "static_replacement" and not static_radio.isEnabled():
                return None
            supplemental_files: list[Path] = []
            for index in range(supplemental_list.count()):
                item = supplemental_list.item(index)
                if item is None or item.checkState() != Qt.Checked:
                    continue
                raw_path = str(item.data(Qt.UserRole) or "")
                if raw_path:
                    supplemental_files.append(Path(raw_path))
            return MeshImportSetupSelection(
                scene_path=scene_path,
                import_mode=import_mode,
                supplemental_files=tuple(supplemental_files),
                scene_import_result=scene_import_result,
            )

        def _start_archive_mesh_export(self, entry: ArchiveEntry, export_format: str) -> None:
            default_dir = self.settings_file_path.parent / "mesh_export"
            output_dir = QFileDialog.getExistingDirectory(
                self,
                f"Export {export_format.upper()}",
                str(default_dir),
            )
            if not output_dir:
                return

            selected_related_entries: Tuple[ArchiveEntry, ...] = ()
            normalized_export_format = export_format.strip().lower()
            if normalized_export_format in {"obj", "fbx"}:
                selected_related_entries_result = self._prompt_archive_mesh_related_file_selection(
                    entry,
                    title=f"Export Referenced Files With {normalized_export_format.upper()}",
                    intro_text=(
                        "Select which resolved referenced files should be copied alongside the mesh export. "
                        "The selected files will be written into a referenced_files/ folder inside the chosen export directory."
                    ),
                    confirm_button_text=f"Export {normalized_export_format.upper()}",
                )
                if selected_related_entries_result is None:
                    return
                selected_related_entries = selected_related_entries_result

            def _launch_export(*, allow_missing_skeleton: bool = False) -> None:
                def _task(log: Callable[[str], None]) -> MeshExportResult:
                    return export_archive_mesh(
                        entry,
                        Path(output_dir),
                        export_format,
                        archive_entries_by_normalized_path=self.archive_entries_by_normalized_path,
                        archive_entries_by_basename=self.archive_entries_by_basename,
                        related_entries=selected_related_entries,
                        allow_missing_skeleton=allow_missing_skeleton,
                        on_log=log,
                    )

                def _handle_complete(result: object) -> None:
                    if not isinstance(result, MeshExportResult):
                        self.set_status_message("Mesh export finished with an unexpected result payload.", error=True)
                        return
                    if result.requires_confirmation:
                        confirmation = QMessageBox.question(
                            self,
                            result.confirmation_title or "Export FBX Without Skeleton?",
                            result.confirmation_message or (
                                "No usable skeleton could be resolved. Continue with a mesh-only FBX export?"
                            ),
                            QMessageBox.Yes | QMessageBox.No,
                            QMessageBox.No,
                        )
                        if confirmation == QMessageBox.Yes:
                            QTimer.singleShot(0, lambda: _launch_export(allow_missing_skeleton=True))
                        else:
                            self.set_status_message(f"Cancelled {export_format.upper()} export for {entry.basename}.")
                        return

                    displayed_paths = [str(path) for path in result.output_paths[:15]]
                    if len(result.output_paths) > 15:
                        displayed_paths.append(f"... {len(result.output_paths) - 15} more file(s)")
                    exported_files = "\n".join(displayed_paths)
                    summary_text = "\n".join(result.summary_lines)
                    QMessageBox.information(
                        self,
                        "Mesh Export Complete",
                        f"{summary_text}\n\nExported files:\n{exported_files}",
                    )
                    self.set_status_message(f"Exported {entry.basename} as {export_format.upper()}.")

                self._run_utility_task(
                    status_message=f"Exporting {entry.basename} as {export_format.upper()}...",
                    task=_task,
                    on_complete=_handle_complete,
                    show_archive_progress=True,
                )

            _launch_export()

        def _prompt_archive_mesh_import_mode(self, entry: Optional[ArchiveEntry] = None) -> Optional[str]:
            dialog = QMessageBox(self)
            dialog.setWindowTitle("Choose Mesh Import Mode")
            dialog.setIcon(QMessageBox.Question)
            dialog.setText("Choose how to import this mesh file.")
            compatibility_note = ""
            profile: Optional[ReplacementAssetProfile] = None
            if entry is not None:
                try:
                    original_data, _decompressed, _note = read_archive_entry_data(entry)
                    profile = analyze_replacement_asset(
                        entry,
                        archive_entries_by_basename=dict(self.archive_entries_by_basename),
                        parsed_mesh=parse_mesh(original_data, entry.path),
                    )
                    compatibility_note = f"\n\nMesh replacement compatibility: {profile.support_level} ({profile.category_hint})."
                    if profile.errors:
                        compatibility_note += "\n" + "\n".join(profile.errors[:2])
                except Exception as exc:
                    compatibility_note = f"\n\nMesh replacement compatibility could not be inspected: {exc}"
            dialog.setInformativeText(
                "Round-trip edit expects an OBJ to keep the original exported mesh structure. "
                "Mesh replacement maps a different OBJ/DAE model onto the original material/draw slots when the target asset is compatible."
                + compatibility_note
            )
            roundtrip_button = dialog.addButton("Round-trip Edit", QMessageBox.AcceptRole)
            static_button = dialog.addButton("Mesh Replacement", QMessageBox.ActionRole)
            if profile is not None and not profile.export_supported:
                static_button.setEnabled(False)
                static_button.setToolTip("\n".join(profile.errors) or "Mesh replacement is not enabled for this asset.")
            dialog.addButton(QMessageBox.Cancel)
            dialog.setDefaultButton(roundtrip_button)
            dialog.exec()
            clicked = dialog.clickedButton()
            if clicked == static_button:
                return "static_replacement"
            if clicked == roundtrip_button:
                return "roundtrip"
            return None

        @staticmethod
        def _format_static_alignment_number(value: object) -> str:
            try:
                number = float(value)
            except (TypeError, ValueError):
                return str(value)
            if abs(number) < 0.000005:
                number = 0.0
            return f"{number:.5f}"

        @classmethod
        def _format_static_alignment_vec(cls, value: object) -> str:
            if not isinstance(value, (list, tuple)) or len(value) != 3:
                return str(value)
            return "(" + ", ".join(cls._format_static_alignment_number(part) for part in value) + ")"

        @classmethod
        def _build_archive_static_placement_context_html(cls, entry: ArchiveEntry, obj_path: Path) -> Tuple[str, Dict[str, object]]:
            try:
                original_data, _decompressed, _note = read_archive_entry_data(entry)
                original_mesh = parse_mesh(original_data, entry.path)
                replacement_mesh = import_scene_mesh(obj_path)
                context_lines = describe_static_placement_context(original_mesh, replacement_mesh)
                parsed: Dict[str, object] = {}
                for line in context_lines:
                    if ": " in line:
                        key, value = line.split(": ", 1)
                        parsed[key.strip().lower()] = value.strip()

                def _parse_axis_length(key: str) -> Tuple[str, float]:
                    value = str(parsed.get(key, "unknown / 0") or "")
                    axis, _sep, raw_length = value.partition("/")
                    try:
                        length = float(raw_length.strip())
                    except ValueError:
                        length = 0.0
                    return axis.strip().upper() or "?", length

                def _parse_vec_from_text(key: str) -> str:
                    value = str(parsed.get(key, "") or "")
                    match = re.search(r"\(([^)]*)\)", value)
                    if not match:
                        return value
                    parts = []
                    for raw_part in match.group(1).split(","):
                        try:
                            parts.append(float(raw_part.strip()))
                        except ValueError:
                            parts.append(raw_part.strip())
                    return cls._format_static_alignment_vec(tuple(parts))

                original_axis, original_length = _parse_axis_length("original axis/length")
                replacement_axis, replacement_length = _parse_axis_length("replacement axis/length")
                try:
                    auto_scale = float(str(parsed.get("auto length scale", "1") or "1"))
                except ValueError:
                    auto_scale = 1.0
                guidance: List[str] = []
                if original_axis != replacement_axis and original_axis != "?" and replacement_axis != "?":
                    guidance.append(
                        f"Axis: replacement is along <b>{replacement_axis}</b>, original is along <b>{original_axis}</b>; auto alignment will rotate between these axes."
                    )
                if auto_scale < 0.95:
                    guidance.append(
                        f"Scale: auto length scale is <b>{cls._format_static_alignment_number(auto_scale)}</b>, so enabled auto-scale will shrink the replacement."
                    )
                elif auto_scale > 1.05:
                    guidance.append(
                        f"Scale: auto length scale is <b>{cls._format_static_alignment_number(auto_scale)}</b>, so enabled auto-scale will enlarge the replacement."
                    )
                else:
                    guidance.append("Scale: replacement and original are already close in length.")
                guidance.append(
                    "Offset: after import, move X/Y/Z in small steps if the anchor point is close but not exactly aligned."
                )
                guidance.append(
                    "Rotation: use this after Auto/Flip if the asset is tilted or rolled around the anchor."
                )
                html = f"""
                <style>
                  .muted {{ color: #9aa0a6; }}
                  .value {{ color: #8ab4f8; font-weight: 600; }}
                  .warn {{ color: #fdd663; font-weight: 600; }}
                  .ok {{ color: #81c995; font-weight: 600; }}
                  table {{ border-collapse: collapse; }}
                  td {{ padding: 2px 10px 2px 0; vertical-align: top; }}
                </style>
                <div>
                  <div class="muted">Tiny values like 3.2471e-07 mean almost zero; this dialog rounds them to 0.00000.</div>
                  <table>
                    <tr><td>Original length axis</td><td class="value">{original_axis}</td><td class="value">{cls._format_static_alignment_number(original_length)}</td></tr>
                    <tr><td>Replacement length axis</td><td class="value">{replacement_axis}</td><td class="value">{cls._format_static_alignment_number(replacement_length)}</td></tr>
                    <tr><td>Auto length scale</td><td colspan="2" class="{'warn' if auto_scale < 0.95 or auto_scale > 1.05 else 'ok'}">{cls._format_static_alignment_number(auto_scale)}</td></tr>
                    <tr><td>Original inferred anchor</td><td colspan="2" class="value">{_parse_vec_from_text("original inferred anchor")}</td></tr>
                    <tr><td>Replacement inferred anchor</td><td colspan="2" class="value">{_parse_vec_from_text("replacement inferred anchor")}</td></tr>
                    <tr><td>Original far end</td><td colspan="2" class="value">{_parse_vec_from_text("original inferred far end")}</td></tr>
                    <tr><td>Replacement far end</td><td colspan="2" class="value">{_parse_vec_from_text("replacement inferred far end")}</td></tr>
                  </table>
                  <div style="margin-top:8px;"><b>Suggested starting point</b></div>
                  <ul>
                    {''.join(f'<li>{item}</li>' for item in guidance)}
                  </ul>
                </div>
                """
                return html, {
                    "auto_scale": auto_scale,
                    "original_axis": original_axis,
                    "replacement_axis": replacement_axis,
                }
            except Exception as exc:
                return f"<span style='color:#fdd663;'>Placement values could not be read automatically: {escape(str(exc))}</span>", {}

        def _add_replacement_asset_profile_summary(
            self,
            parent_layout: QVBoxLayout,
            profile: ReplacementAssetProfile,
        ) -> None:
            theme = get_theme(self.current_theme_key)
            support_colors = {
                "Supported": "#86efac",
                "Experimental": "#facc15",
                "Preview only": "#93c5fd",
                "Blocked": "#fca5a5",
            }
            group = QGroupBox("Asset Compatibility")
            group_layout = QVBoxLayout(group)
            group_layout.setSpacing(10)
            facts = {str(label): str(value) for label, value in profile.facts}

            chip_row = QHBoxLayout()
            chip_row.setSpacing(8)

            def _chip(label_text: str, value_text: str, color: str = "") -> QLabel:
                chip = QLabel(f"{label_text}: {value_text}")
                chip.setTextInteractionFlags(Qt.TextSelectableByMouse)
                chip.setStyleSheet(
                    "QLabel {"
                    f"background: {theme['surface_alt']};"
                    f"border: 1px solid {theme['border']};"
                    "border-radius: 4px;"
                    "padding: 4px 8px;"
                    f"color: {color or theme['text']};"
                    "font-weight: 600;"
                    "}"
                )
                return chip

            for label_text in ("Support", "Format", "Category", "Family"):
                value_text = facts.get(label_text)
                if value_text:
                    chip_row.addWidget(
                        _chip(
                            label_text,
                            value_text,
                            support_colors.get(value_text, "") if label_text == "Support" else "",
                        )
                    )
            chip_row.addStretch(1)
            group_layout.addLayout(chip_row)

            metric_labels = {"Submeshes", "Faces", "Vertices", "UVs", "Skinning", "LOD", "Sidecar", "Texture slots"}
            metrics_grid = QGridLayout()
            metrics_grid.setHorizontalSpacing(16)
            metrics_grid.setVerticalSpacing(5)
            metric_index = 0
            for label_text, value_text in profile.facts:
                if label_text not in metric_labels:
                    continue
                label = QLabel(label_text)
                label.setObjectName("HintLabel")
                value = QLabel(value_text)
                value.setWordWrap(True)
                value.setMinimumWidth(0)
                value.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Preferred)
                value.setTextInteractionFlags(Qt.TextSelectableByMouse)
                value.setStyleSheet(f"color: {theme['text_strong']};")
                row = metric_index // 2
                column = (metric_index % 2) * 2
                metrics_grid.addWidget(label, row, column)
                metrics_grid.addWidget(value, row, column + 1)
                metric_index += 1
            if metric_index:
                group_layout.addLayout(metrics_grid)

            related_by_role: Dict[str, List[str]] = {}
            for related in profile.related_files:
                related_by_role.setdefault(related.role, []).append(PurePosixPath(related.path).name)
            related_summary = "None found"
            if related_by_role:
                related_summary = " | ".join(
                    f"{role}: {', '.join(names[:3])}" + (" ..." if len(names) > 3 else "")
                    for role, names in related_by_role.items()
                )
            related_label = QLabel(f"Related files\n{related_summary}")
            related_label.setWordWrap(True)
            related_label.setMinimumWidth(0)
            related_label.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Preferred)
            related_label.setObjectName("HintLabel")
            related_label.setTextInteractionFlags(Qt.TextSelectableByMouse)
            group_layout.addWidget(related_label)

            if getattr(profile, "required_companions", ()):
                companion_names = [PurePosixPath(path).name for path in profile.required_companions[:8]]
                companions_label = QLabel(
                    "Required companions\n"
                    + ", ".join(companion_names)
                    + (" ..." if len(profile.required_companions) > len(companion_names) else "")
                )
                companions_label.setWordWrap(True)
                companions_label.setMinimumWidth(0)
                companions_label.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Preferred)
                companions_label.setObjectName("HintLabel")
                companions_label.setTextInteractionFlags(Qt.TextSelectableByMouse)
                companions_label.setToolTip("\n".join(profile.required_companions[:80]))
                group_layout.addWidget(companions_label)

            if profile.texture_summary:
                texture_summary = " | ".join(
                    f"{label}: {value}" for label, value in profile.texture_summary[:8]
                )
                texture_label = QLabel(f"Texture slots\n{texture_summary}")
                texture_label.setWordWrap(True)
                texture_label.setMinimumWidth(0)
                texture_label.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Preferred)
                texture_label.setObjectName("HintLabel")
                texture_label.setTextInteractionFlags(Qt.TextSelectableByMouse)
                group_layout.addWidget(texture_label)

            messages = list(profile.errors) + list(profile.warnings)
            if messages:
                message_label = QLabel("\n".join(f"- {message}" for message in messages[:6]))
                message_label.setWordWrap(True)
                message_label.setTextInteractionFlags(Qt.TextSelectableByMouse)
                message_label.setStyleSheet("color: #fca5a5;" if profile.errors else "color: #facc15;")
                group_layout.addWidget(message_label)
            parent_layout.addWidget(group)

        def _prompt_archive_static_replacement_options(
            self,
            entry: ArchiveEntry,
            obj_path: Path,
            supplemental_files: Sequence[Path] = (),
            import_diagnostics: Sequence[str] = (),
        ) -> Optional[StaticMeshReplacementOptions]:
            dialog = QDialog(self)
            dialog.setWindowTitle("Mesh Replacement Alignment")
            dialog.setMinimumSize(1120, 700)
            dialog.setSizeGripEnabled(True)
            root_layout = QVBoxLayout(dialog)
            main_splitter = QSplitter(Qt.Horizontal, dialog)
            content_scroll = QScrollArea(dialog)
            content_scroll.setWidgetResizable(True)
            content_scroll.setHorizontalScrollBarPolicy(Qt.ScrollBarAlwaysOff)
            content_scroll.setVerticalScrollBarPolicy(Qt.ScrollBarAsNeeded)
            content_scroll.setFrameShape(QFrame.NoFrame)
            content_scroll.setMinimumWidth(360)
            content_scroll.setMaximumWidth(620)
            content_container = QWidget()
            content_container.setMinimumWidth(0)
            content_container.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Preferred)
            layout = QVBoxLayout(content_container)
            layout.setContentsMargins(8, 8, 8, 8)
            layout.setSpacing(8)
            content_scroll.setWidget(content_container)
            main_splitter.addWidget(content_scroll)
            preview_panel = QWidget(dialog)
            preview_panel.setMinimumWidth(420)
            preview_panel_layout = QVBoxLayout(preview_panel)
            preview_header = QHBoxLayout()
            preview_header.addWidget(QLabel("Live Alignment Preview"))
            preview_header.addStretch(1)
            preview_mode_combo = QComboBox()
            preview_mode_combo.addItem("Side by side", "side_by_side")
            preview_mode_combo.addItem("Overlay", "overlay")
            preview_mode_combo.addItem("Replacement only", "replacement_only")
            preview_mode_combo.setToolTip("Side by side compares original and replacement. Overlay draws both in one view. Replacement only gives more room to inspect the imported asset.")
            preview_header.addWidget(QLabel("Preview mode"))
            preview_header.addWidget(preview_mode_combo)
            overlay_original_locked_checkbox = QCheckBox("Original locked")
            overlay_original_locked_checkbox.setChecked(True)
            overlay_original_locked_checkbox.setEnabled(False)
            overlay_original_locked_checkbox.setToolTip("In Overlay mode, keep the original reference fixed and move only the replacement preview.")
            preview_header.addWidget(overlay_original_locked_checkbox)
            alignment_preview_settings_button = QPushButton("3D Preview Settings...")
            alignment_preview_settings_button.setToolTip("Open the global 3D preview settings used by archive, material, import, and alignment previews.")
            alignment_use_global_preview_button = QPushButton("Use Global")
            alignment_use_global_preview_button.setToolTip("Reset the alignment preview controls to the current global 3D preview settings.")
            preview_header.addWidget(alignment_preview_settings_button)
            preview_header.addWidget(alignment_use_global_preview_button)
            preview_panel_layout.addLayout(preview_header)
            preview_render_settings = self._current_model_preview_render_settings()
            preview_render_controls = QHBoxLayout()
            preview_render_controls.setSpacing(8)
            preview_visible_mode_combo = QComboBox()
            for mode in MODEL_PREVIEW_VISIBLE_TEXTURE_MODES:
                preview_visible_mode_combo.addItem(MODEL_PREVIEW_VISIBLE_TEXTURE_MODE_LABELS.get(mode, mode), mode)
            visible_index = preview_visible_mode_combo.findData(preview_render_settings.visible_texture_mode)
            preview_visible_mode_combo.setCurrentIndex(max(0, visible_index))
            preview_visible_mode_combo.setToolTip("Texture-selection strategy for alignment preview rebuilds.")
            preview_render_mode_combo = QComboBox()
            for mode in MODEL_PREVIEW_RENDER_DIAGNOSTIC_MODES:
                preview_render_mode_combo.addItem(MODEL_PREVIEW_RENDER_DIAGNOSTIC_MODE_LABELS.get(mode, mode), mode)
            render_index = preview_render_mode_combo.findData(preview_render_settings.render_diagnostic_mode)
            preview_render_mode_combo.setCurrentIndex(max(0, render_index))
            preview_render_mode_combo.setToolTip("Render mode for the live alignment preview.")
            preview_disable_tint_checkbox = QCheckBox("No tint")
            preview_disable_tint_checkbox.setChecked(bool(preview_render_settings.disable_tint))
            preview_disable_tint_checkbox.setToolTip("Ignore sidecar tint in this alignment preview.")
            preview_disable_brightness_checkbox = QCheckBox("No brightness")
            preview_disable_brightness_checkbox.setChecked(bool(preview_render_settings.disable_brightness))
            preview_disable_brightness_checkbox.setToolTip("Ignore sidecar brightness multiplier in this alignment preview.")
            preview_disable_uv_scale_checkbox = QCheckBox("No UV scale")
            preview_disable_uv_scale_checkbox.setChecked(bool(preview_render_settings.disable_uv_scale))
            preview_disable_uv_scale_checkbox.setToolTip("Ignore sidecar UV scale in this alignment preview.")
            preview_render_controls.addWidget(QLabel("Visible"))
            preview_render_controls.addWidget(preview_visible_mode_combo, 1)
            preview_render_controls.addWidget(QLabel("Render"))
            preview_render_controls.addWidget(preview_render_mode_combo, 1)
            preview_render_controls.addWidget(preview_disable_tint_checkbox)
            preview_render_controls.addWidget(preview_disable_brightness_checkbox)
            preview_render_controls.addWidget(preview_disable_uv_scale_checkbox)
            preview_panel_layout.addLayout(preview_render_controls)
            preview_splitter = QSplitter(Qt.Horizontal, preview_panel)
            original_preview_container = QWidget(preview_splitter)
            original_preview_layout = QVBoxLayout(original_preview_container)
            original_preview_layout.setContentsMargins(0, 0, 0, 0)
            original_preview_layout.addWidget(QLabel("Original Reference"))
            original_dialog_preview = ModelPreviewWidget("Original asset reference preview.", theme_key=self.current_theme_key)
            original_dialog_preview.setMinimumSize(300, 340)
            original_dialog_preview.set_render_settings(preview_render_settings)
            original_dialog_preview.set_use_textures(True)
            original_dialog_preview.set_high_quality_textures(True)
            original_dialog_preview.set_alignment_guides_visible(True)
            original_preview_layout.addWidget(original_dialog_preview, 1)
            replacement_preview_container = QWidget(preview_splitter)
            replacement_preview_layout = QVBoxLayout(replacement_preview_container)
            replacement_preview_layout.setContentsMargins(0, 0, 0, 0)
            replacement_preview_layout.addWidget(QLabel("Replacement With Current Mapping"))
            static_dialog_preview = ModelPreviewWidget("Select texture slots to preview.", theme_key=self.current_theme_key)
            static_dialog_preview.setMinimumSize(340, 340)
            static_dialog_preview.set_render_settings(preview_render_settings)
            static_dialog_preview.set_use_textures(True)
            static_dialog_preview.set_high_quality_textures(True)
            static_dialog_preview.set_alignment_guides_visible(True)
            static_dialog_preview.set_alignment_editing_enabled(True)
            replacement_preview_layout.addWidget(static_dialog_preview, 1)
            preview_splitter.addWidget(original_preview_container)
            preview_splitter.addWidget(replacement_preview_container)
            preview_splitter.setCollapsible(0, False)
            preview_splitter.setCollapsible(1, False)
            preview_splitter.setStretchFactor(0, 1)
            preview_splitter.setStretchFactor(1, 2)
            preview_splitter.setSizes([420, 620])
            overlay_dialog_preview = ModelPreviewWidget("Overlay preview.", theme_key=self.current_theme_key)
            overlay_dialog_preview.setMinimumSize(520, 380)
            overlay_dialog_preview.set_render_settings(preview_render_settings)
            overlay_dialog_preview.set_use_textures(True)
            overlay_dialog_preview.set_high_quality_textures(True)
            overlay_dialog_preview.set_alignment_guides_visible(True)
            overlay_dialog_preview.set_alignment_editing_enabled(True)
            replacement_only_preview = ModelPreviewWidget("Replacement preview.", theme_key=self.current_theme_key)
            replacement_only_preview.setMinimumSize(520, 380)
            replacement_only_preview.set_render_settings(preview_render_settings)
            replacement_only_preview.set_use_textures(True)
            replacement_only_preview.set_high_quality_textures(True)
            replacement_only_preview.set_alignment_guides_visible(True)
            replacement_only_preview.set_alignment_editing_enabled(True)

            def _current_alignment_preview_render_settings() -> ModelPreviewRenderSettings:
                return clamp_model_preview_render_settings(
                    dataclasses.replace(
                        preview_render_settings,
                        visible_texture_mode=str(
                            preview_visible_mode_combo.currentData()
                            or preview_render_settings.visible_texture_mode
                        ),
                        render_diagnostic_mode=str(
                            preview_render_mode_combo.currentData()
                            or preview_render_settings.render_diagnostic_mode
                        ),
                        disable_tint=preview_disable_tint_checkbox.isChecked(),
                        disable_brightness=preview_disable_brightness_checkbox.isChecked(),
                        disable_uv_scale=preview_disable_uv_scale_checkbox.isChecked(),
                    )
                )

            def _apply_alignment_preview_render_settings(*_args) -> None:
                nonlocal preview_render_settings
                preview_render_settings = _current_alignment_preview_render_settings()
                for preview_widget in (
                    original_dialog_preview,
                    static_dialog_preview,
                    overlay_dialog_preview,
                    replacement_only_preview,
                ):
                    preview_widget.set_render_settings(preview_render_settings)
                    preview_widget.set_use_textures(True)
                    preview_widget.set_high_quality_textures(True)
                _queue_static_preview_refresh()

            def _sync_alignment_preview_controls_from_settings(settings: ModelPreviewRenderSettings) -> None:
                for combo, value in (
                    (preview_visible_mode_combo, settings.visible_texture_mode),
                    (preview_render_mode_combo, settings.render_diagnostic_mode),
                ):
                    combo.blockSignals(True)
                    combo_index = combo.findData(value)
                    combo.setCurrentIndex(max(0, combo_index))
                    combo.blockSignals(False)
                for checkbox, value in (
                    (preview_disable_tint_checkbox, settings.disable_tint),
                    (preview_disable_brightness_checkbox, settings.disable_brightness),
                    (preview_disable_uv_scale_checkbox, settings.disable_uv_scale),
                ):
                    checkbox.blockSignals(True)
                    checkbox.setChecked(bool(value))
                    checkbox.blockSignals(False)

            def _use_global_alignment_preview_settings() -> None:
                nonlocal preview_render_settings
                preview_render_settings = self._current_model_preview_render_settings()
                _sync_alignment_preview_controls_from_settings(preview_render_settings)
                _apply_alignment_preview_render_settings()

            preview_visible_mode_combo.currentIndexChanged.connect(_apply_alignment_preview_render_settings)
            preview_render_mode_combo.currentIndexChanged.connect(_apply_alignment_preview_render_settings)
            preview_disable_tint_checkbox.toggled.connect(_apply_alignment_preview_render_settings)
            preview_disable_brightness_checkbox.toggled.connect(_apply_alignment_preview_render_settings)
            preview_disable_uv_scale_checkbox.toggled.connect(_apply_alignment_preview_render_settings)
            alignment_preview_settings_button.clicked.connect(
                lambda _checked=False, parent_dialog=dialog: self._open_modal_model_preview_settings_dialog(parent_dialog)
            )
            alignment_use_global_preview_button.clicked.connect(_use_global_alignment_preview_settings)
            preview_stack = QStackedWidget(preview_panel)
            preview_stack.addWidget(preview_splitter)
            preview_stack.addWidget(overlay_dialog_preview)
            preview_stack.addWidget(replacement_only_preview)
            preview_panel_layout.addWidget(preview_stack, 1)
            preview_help = QLabel(
                "The preview updates with the current mapping, transform, and selected texture slots before the mesh is rebuilt."
            )
            preview_help.setWordWrap(True)
            preview_help.setObjectName("HintLabel")
            preview_panel_layout.addWidget(preview_help)
            main_splitter.addWidget(preview_panel)
            main_splitter.setCollapsible(0, False)
            main_splitter.setCollapsible(1, False)
            main_splitter.setStretchFactor(0, 0)
            main_splitter.setStretchFactor(1, 1)
            main_splitter.setSizes([560, 1180])
            root_layout.addWidget(main_splitter, 1)

            control_tabs = QTabWidget(content_container)
            control_tabs.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Maximum)
            setup_tab = QWidget(control_tabs)
            setup_layout = QVBoxLayout(setup_tab)
            setup_layout.setContentsMargins(8, 8, 8, 8)
            setup_layout.setSpacing(8)
            setup_layout.setAlignment(Qt.AlignTop)
            parts_tab = QWidget(control_tabs)
            parts_layout = QVBoxLayout(parts_tab)
            parts_layout.setContentsMargins(8, 8, 8, 8)
            parts_layout.setSpacing(8)
            parts_layout.setAlignment(Qt.AlignTop)
            textures_tab = QWidget(control_tabs)
            textures_layout = QVBoxLayout(textures_tab)
            textures_layout.setContentsMargins(8, 8, 8, 8)
            textures_layout.setSpacing(8)
            textures_layout.setAlignment(Qt.AlignTop)
            control_tabs.addTab(setup_tab, "Setup")
            control_tabs.addTab(parts_tab, "Parts")
            control_tabs.addTab(textures_tab, "Textures")
            layout.addWidget(control_tabs, 0)
            intro = QLabel(
                "Choose alignment behavior and safety options. Changes update the preview before the mesh is rebuilt."
            )
            intro.setWordWrap(True)
            intro.setObjectName("HintLabel")
            setup_layout.addWidget(intro)
            if import_diagnostics:
                import_group = QGroupBox("Import Notes")
                import_layout = QVBoxLayout(import_group)
                for line in list(import_diagnostics)[:8]:
                    note = QLabel(str(line))
                    note.setWordWrap(True)
                    note.setObjectName("HintLabel")
                    import_layout.addWidget(note)
                setup_layout.addWidget(import_group)

            context_html, context_values = self._build_archive_static_placement_context_html(entry, obj_path)
            context_group = QGroupBox("Alignment Summary")
            context_layout = QGridLayout(context_group)
            original_axis_text = str(context_values.get("original_axis", "?") or "?")
            replacement_axis_text = str(context_values.get("replacement_axis", "?") or "?")
            auto_scale_value = float(context_values.get("auto_scale", 1.0) or 1.0)
            compact_facts = (
                ("Original axis", original_axis_text),
                ("Replacement axis", replacement_axis_text),
                ("Auto length scale", self._format_static_alignment_number(auto_scale_value)),
                ("Suggested workflow", "Start with Alignment mode: Auto and toggle Flip direction 180 if needed, then fine tune Transform."),
            )
            for fact_row, (fact_label, fact_value) in enumerate(compact_facts):
                label_widget = QLabel(fact_label)
                label_widget.setObjectName("HintLabel")
                value_widget = QLabel(fact_value)
                value_widget.setWordWrap(True)
                value_widget.setMinimumWidth(0)
                value_widget.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Preferred)
                value_widget.setTextInteractionFlags(Qt.TextSelectableByMouse)
                context_layout.addWidget(label_widget, fact_row, 0)
                context_layout.addWidget(value_widget, fact_row, 1)
            context_group.setToolTip(context_html)
            setup_layout.addWidget(context_group)

